/*Table structure for table `camera_config` */

DROP TABLE IF EXISTS `camera_config`;

CREATE TABLE `camera_config` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `config_key` varchar(50) NOT NULL COMMENT '配置键',
  `config_value` varchar(500) DEFAULT NULL COMMENT '配置值',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_config_key` (`config_key`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COMMENT='摄像头配置表';

/*Data for the table `camera_config` */

insert  into `camera_config`(`id`,`config_key`,`config_value`,`remark`,`create_time`,`update_time`) values (1,'storage_path','/data/camera/record','录像存储路径',NULL,NULL),(2,'storage_max_size','10737418240','最大存储(10G)',NULL,NULL),(3,'screenshot_path','/data/camera/screenshot','截图存储路径',NULL,NULL),(4,'scan_timeout','3000','扫描超时(ms)',NULL,NULL),(5,'stream_proxy_port','8554','流代理端口',NULL,NULL);

/*Table structure for table `camera_device` */

DROP TABLE IF EXISTS `camera_device`;

CREATE TABLE `camera_device` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(100) NOT NULL COMMENT '设备名称',
  `brand` varchar(50) DEFAULT 'general' COMMENT '品牌(haikang/dahua/yushi/tplink/general)',
  `ip` varchar(50) NOT NULL COMMENT 'IP地址',
  `port` int(11) DEFAULT '554' COMMENT 'RTSP端口',
  `http_port` int(11) DEFAULT '80' COMMENT 'HTTP端口',
  `username` varchar(100) DEFAULT NULL COMMENT '用户名',
  `password` varchar(100) DEFAULT NULL COMMENT '密码(加密)',
  `channel` int(11) DEFAULT '1' COMMENT '通道号',
  `stream_type` varchar(20) DEFAULT 'main' COMMENT '码流(main主码流/sub子码流)',
  `status` tinyint(1) DEFAULT '0' COMMENT '在线状态(0离线1在线)',
  `last_online_time` int(11) DEFAULT NULL COMMENT '最后在线时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` tinyint(1) DEFAULT '0' COMMENT '删除标志(0正常1删除)',
  PRIMARY KEY (`id`),
  KEY `idx_ip` (`ip`),
  KEY `idx_brand` (`brand`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摄像头设备表';

/*Data for the table `camera_device` */

/*Table structure for table `camera_record` */

DROP TABLE IF EXISTS `camera_record`;

CREATE TABLE `camera_record` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `device_id` int(11) NOT NULL COMMENT '设备ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(255) NOT NULL COMMENT '文件路径',
  `file_size` bigint(20) DEFAULT '0' COMMENT '文件大小(字节)',
  `duration` int(11) DEFAULT '0' COMMENT '时长(秒)',
  `start_time` int(11) DEFAULT NULL COMMENT '开始时间戳',
  `end_time` int(11) DEFAULT NULL COMMENT '结束时间戳',
  `record_type` varchar(20) DEFAULT 'manual' COMMENT '录像类型(manual手动/timing定时/motion移动侦测)',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态(0生成中1已完成)',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_start_time` (`start_time`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摄像头录像表';

/*Data for the table `camera_record` */

/*Table structure for table `camera_screenshot` */

DROP TABLE IF EXISTS `camera_screenshot`;

CREATE TABLE `camera_screenshot` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `device_id` int(11) NOT NULL COMMENT '设备ID',
  `file_path` varchar(255) NOT NULL COMMENT '文件路径',
  `file_size` bigint(20) DEFAULT '0' COMMENT '文件大小',
  `snapshot_time` int(11) DEFAULT NULL COMMENT '截图时间戳',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_snapshot_time` (`snapshot_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摄像头截图表';

