/*Table structure for table `la_article` */

DROP TABLE IF EXISTS `la_article`;

CREATE TABLE `la_article` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '文章id',
  `cid` int(11) NOT NULL COMMENT '文章分类',
  `title` varchar(255) NOT NULL COMMENT '文章标题',
  `desc` varchar(255) DEFAULT '' COMMENT '简介',
  `abstract` text COMMENT '文章摘要',
  `image` varchar(128) DEFAULT NULL COMMENT '文章图片',
  `author` varchar(255) DEFAULT '' COMMENT '作者',
  `content` longtext COMMENT '文章内容',
  `click_virtual` int(10) DEFAULT '0' COMMENT '虚拟浏览量',
  `click_actual` int(11) DEFAULT '0' COMMENT '实际浏览量',
  `is_show` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示:1-是.0-否',
  `sort` int(5) DEFAULT '0' COMMENT '排序',
  `create_time` int(11) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(11) DEFAULT NULL COMMENT '更新时间',
  `delete_time` int(11) DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=90 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='文章表';

/*Data for the table `la_article` */

insert  into `la_article`(`id`,`cid`,`title`,`desc`,`abstract`,`image`,`author`,`content`,`click_virtual`,`click_actual`,`is_show`,`sort`,`create_time`,`update_time`,`delete_time`) values (4,5,'Mybatis中#{}和${}的区别','Mybatis中#{}和${}的区别','','','Amusing编程喵','<p>1、1）#{} 为参数占位符 ?，即sql 预编译</p><p>　 &nbsp;2）${} 为字符串替换，即 sql 拼接</p><p>2、1）变量替换后，#{} 对应的变量自动加上单引号 \'\'</p><p>　 &nbsp;2）变量替换后，${} 对应的变量不会加上单引号 \'\'</p><p>3、#{} 和 ${} 的实例：假设传入参数为 1</p><p> （1）开始</p><p> &nbsp; &nbsp; &nbsp; &nbsp;1）#{}：select * from t_user where uid=#{uid}</p><p> &nbsp; &nbsp; &nbsp; &nbsp;2）${}：select * from t_user where uid= \'${uid}\'</p><p> （2）然后</p><p> &nbsp; &nbsp; &nbsp; &nbsp;1）#{}：select * from t_user where uid= ?</p><p> &nbsp; &nbsp; &nbsp; &nbsp;2）${}：select * from t_user where uid= \'1\'</p><p> （3）最后</p><p>　　1）#{}：select * from t_user where uid= \'1\'</p><p>　　2）${}：select * from t_user where uid= \'1\'</p><p>4、1）#{} 能防止sql 注入</p><p> &nbsp; &nbsp; &nbsp;2）${} 不能防止sql 注入</p><p>5、#{} 和 ${} 在使用中的技巧和建议</p><p>（1）不论是单个参数，还是多个参数，一律都建议使用注解@Param(\"\")</p><p>（2）能用 #{} 的地方就用 #{}，不用或少用 ${}</p><p>（3）表名作参数时，必须用 ${}。如：select * from ${tableName}</p><p>（4）order by 时，必须用 ${}。如：select * from t_user order by ${columnName}</p><p>（5）使用 ${} 时，要注意何时加或不加单引号，即 ${} 和 \'${}\'</p>',0,6,0,0,1753454126,1754123888,1754747035),(5,6,'SQLServer常见问题','SQLServer常见问题','','','Amusing编程喵','<p><strong>一、[Err] 42000 - [SQL Server]“offset”附近有语法错误。42000 - [SQL Server]在 FETCH 语句中选项 NEXT 的用法无效。</strong></p><p> 1、版本问题</p><p> &nbsp; sqlserver2012及之后的版本</p><p> 2、必须有order by</p><p><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/98a9dfd4-5448-4bcd-8289-db79e7200850.png\" alt=\"\" data-href=\"\" style=\"\"/></p><p><strong>二、Error getting generated key or setting result to parameter object, cause: Error</strong></p><p> 可能是数据库ID自增的问题，mybait又设置了值</p><p><strong>三、sqlserver当IDENTITY_INSERT设置为OFF时，不能为表‘XXX‘ 中的标识列插入显式值</strong></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid25_1730038651965.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/2250fea9-c217-4c1d-a820-3c8892ff39b7.png\" alt=\"\" data-href=\"\" style=\"\"></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid26_1730038652023.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/486bbfac-90a3-4da5-abe9-fe9d14ced0da.png\" alt=\"\" data-href=\"\" style=\"width: 643.00px;height: 310.12px;\"></p><p><strong>四、sqlserver多次为 \'totalData\' 指定了列 \'EmpGuid</strong>\'</p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/mceclip2_1730038696168.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/e0df43ef-9551-4ba5-8c31-55aa168fd777.png\" alt=\"\" data-href=\"\" style=\"width: 645.00px;height: 632.89px;\"></p><p><strong>五、sqlserver无法连接</strong></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid27_1730038723962.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/80bd5942-57d3-44e4-a24a-af1c44c9200a.png\" alt=\"\" data-href=\"\" style=\"width: 767.00px;height: 202.70px;\"></p><p> 如果是内网服务器，使用内网连接，而不是公网</p><p><strong>六、解决sql server保存对象字符串转换成uniqueidentifier失败的问题</strong></p><p> 使用UUID带-形式</p><p><strong>七、数据查询特别慢的问题</strong></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid28_1730038821357.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/c43c374f-96a0-4cef-b234-a5f7f9a141e5.png\" alt=\"\" data-href=\"\" style=\"\"></p><p> 可能类型原因，不去查这个字段</p><p><strong>八、sqlServer ------com.microsoft.sqlserver.jdbc.SQLServerException: 必须执行该语句才能获得结果</strong></p><p> mybatis plus非sql使用sqlserver新增有问题</p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid29_1730038925977.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/979d0317-5be3-4e91-9c9f-9101f500ef39.png\" alt=\"\" data-href=\"\" style=\"\"></p><p> 自定义id不行，不指定id，打印sql id为空</p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid30_1730038926041.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/13569cb2-08fc-4a1d-b5c3-4806078ef1d6.png\" alt=\"\" data-href=\"\" style=\"width: 862.00px;height: 223.11px;\"></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid31_1730038925992.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/19f655bf-c6d0-4286-b180-2336c7a82126.png\" alt=\"\" data-href=\"\" style=\"width: 810.00px;height: 424.87px;\"></p><p style=\"text-align: center;\"><img src=\"../jeecgboot/sys/common/static/jeditor/blobid32_1730038925999.png\" alt=\"\" data-href=\"\" style=\"\"><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/11fd99bb-806e-444c-9b5f-85eda9d21a3b.png\" alt=\"\" data-href=\"\" style=\"width: 825.00px;height: 156.83px;\"></p><p> mybatis sql 不写id</p><p><br></p><p> </p><p> </p><p> </p><p> </p><p> </p>',0,25,0,0,1753454491,1754123888,1754747032),(6,5,'test','test','','','Amusing编程喵','<p>test</p><p>test</p><p>test<img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/80bd5942-57d3-44e4-a24a-af1c44c9200a.png\" alt=\"\" data-href=\"\" style=\"\"/><img src=\"http://zy.wlown.com/adminapi/uploads/image/20250725/e0df43ef-9551-4ba5-8c31-55aa168fd777.png\" alt=\"\" data-href=\"\" style=\"\"/></p>',0,139,0,0,1753507618,1753800169,1753800172),(7,5,'test1','test1','','','Amusing编程喵','<p>test1</p><p>test1</p><p>test1</p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250725/11fd99bb-806e-444c-9b5f-85eda9d21a3b.png\" alt=\"\" data-href=\"\" style=\"\"/></p>',0,5,1,0,1753800203,1754123945,1754747038),(8,4,'【环境搭建】Windows环境搭建Vue开发环境','快速轻松上手','Windows环境搭建Vue开发环境','/adminapi/uploads/image/20250809/c2b9e86e-e35d-404d-9011-1c617b85ce11.png','Amusing编程喵','<p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>一、安装node.js</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;官网：</span><a href=\"https://nodejs.org/en/download/\" target=\"\"><span style=\"font-family: 宋体;\">https://nodejs.org/en/download/</span></a></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;历史版本：</span><a href=\"https://nodejs.org/en/download/releases/\" target=\"\"><span style=\"font-family: 宋体;\">https://nodejs.org/en/download/releases/</span></a></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/d5847f99-b368-4231-b893-019e1e00e9c1.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;下载完毕后，可以安装node，建议不要安装在系统盘（如C：）。</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/ff5d9a7c-c7f7-4a1f-8791-b95bc8f5a106.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>二、设置nodejs prefix（全局）和cache（缓存）路径</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;1、在nodejs安装路径下，新建node_global和node_cache两个文件夹。</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/d88a8a81-f078-4298-8097-b963aa446749.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;2、设置缓存文件夹</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; npm config set cache \"D:\\software\\NodeJs\\node_cache\"，设置全局模块存放路径</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; npm config set prefix \"D:\\software\\NodeJs\\node_global\"，设置成功后，之后用命令npm install XXX -g安装以后模块就在D:\\vueProject\\nodejs\\node_global里</span></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>三、基于 Node.js 安装cnpm（淘宝镜像）</strong></span></p><pre><code class=\"language-bash\">npm install -g cnpm --registry=https://registry.npm.taobao.org</code></pre><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>四、设置环境变量（非常重要）</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;说明：设置环境变量可以使得住任意目录下都可以使用cnpm、vue等命令，而不需要输入全路径</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;1、鼠标右键\"此电脑\"，选择“属性”菜单，在弹出的“系统”对话框中左侧选择“高级系统设置”，弹出“系统属性”对话框。</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;2、修改系统变量PATH</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/5a34c7a5-87c1-4bfb-adee-3ad4546e1693.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;3、新增系统变量NODE_PATH</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/0f4ecfa5-5be8-4f48-98b0-75f82ad62547.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>五、安装Vue</strong></span></p><pre><code >cnpm install vue -g</code></pre><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/f1ed2514-ca96-4fe9-a0a3-c704b896c60b.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>六、安装vue命令行工具，即vue-cli 脚手架</strong></span></p><pre><code >cnpm install vue-cli -g</code></pre><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/ec83971e-0927-4878-8eee-aa89d2dbe3c0.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>七、新项目的创建</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;1、打开存放新建项目的文件夹</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;打开开始菜单，输入 CMD，或使用快捷键 win+R，输入 CMD，敲回车，弹出命令提示符。打开你将要新建的项目目录</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/0bd9ced8-2991-4f92-acb3-d5c2cd144ec5.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 2、根据模版创建新项目</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 在当前目录下输入“vue init webpack-simple 项目名称（使用英文）”。</span></p><pre><code >vue init webpack-simple mytest</code></pre><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/a7b96336-dca2-4daa-8f6a-d30b6460a316.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;初始化完成后的项目目录结构如下：</span></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/3809da00-3463-41f9-bfce-efc15dc856d8.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/3d50cb25-d8b3-406c-899c-e221cdff985f.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 3、安装工程依赖模块</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 定位到mytest的工程目录下，安装该工程依赖的模块，这些模块将被安装在：mytest\\node_module目录下，node_module文件夹会被新建，而且根据package.json的配置下载该项目的modules</span></p><pre><code >cd mytest\ncnpm install</code></pre><p style=\"line-height: 2;\"> &nbsp; &nbsp; 4、运行该项目，测试一下该项目是否能够正常工作，这种方式是用nodejs来启动。</p><pre><code >cnpm run dev</code></pre><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/7cd65cf4-91d0-48f9-b657-34c27e6b46e1.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"text-align: center; line-height: 2;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250809/ebbd496f-2a7f-4d9f-972e-9b1e47a2ef12.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>八、借鉴网址</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"><strong> &nbsp; &nbsp;</strong></span><a href=\"https://www.cnblogs.com/zhouyu2017/p/6485265.html\" target=\"\"><span style=\"font-family: 宋体;\">https://www.cnblogs.com/zhouyu2017/p/6485265.html</span></a></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;</span><a href=\"https://www.cnblogs.com/ixxonline/p/6007885.html\" target=\"\"><span style=\"font-family: 宋体;\">https://www.cnblogs.com/ixxonline/p/6007885.html</span></a></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;</span><a href=\"http://blog.csdn.net/zhuming3834/article/details/72778147\" target=\"\"><span style=\"font-family: 宋体;\">http://blog.csdn.net/zhuming3834/article/details/72778147</span></a></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;</span><a href=\"https://www.cnblogs.com/fisheleven/p/6775380.html?utm_source=itdadao&amp;utm_medium=referral\" target=\"\"><span style=\"font-family: 宋体;\">https://www.cnblogs.com/fisheleven/p/6775380.html?utm_source=itdadao&amp;utm_medium=referral</span></a></p>',0,25,1,0,1754750280,1756458408,NULL),(9,4,'CentOS中Mysql rpm安装与配置','CentOS中Mysql rpm安装与配置','CentOS中Mysql rpm安装与配置','/adminapi/uploads/image/20250810/2b8c769e-c93c-4661-8472-fa7925854a5b.png','Amusing编程喵','<h5 style=\"line-height: 3;\">1、首先进入本机的源文件目录</h5><pre><code >cd /usr/local/src</code></pre><h5 style=\"line-height: 3;\">2、使用wget下载官方yum源的rpm包</h5><pre><code >wget https://dev.mysql.com/get/mysql57-community-release-el7-11.noarch.rpm</code></pre><h5 style=\"line-height: 3;\">3、安装rpm包</h5><pre><code >rpm -ivh mysql57-community-release-el7-11.noarch.rpm</code></pre><h5 style=\"line-height: 3;\">4、再次使用yum来安装mysql-server，可以看到这次不再提示安装Mariadb了</h5><pre><code >yum install -y mysql-server</code></pre><h5 style=\"line-height: 3;\">5、安装完成后，启动mysqld服务</h5><pre><code >systemctl start mysqld</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;查看是否成功启动：</p><pre><code >ps aux|grep mysqld</code></pre><h5 style=\"line-height: 3;\">6、设置mysqld服务开机自启动</h5><pre><code >systemctl enable mysqld</code></pre><h5 style=\"line-height: 3;\"><strong>7、使用初始密码登录</strong></h5><p style=\"line-height: 3;\"> &nbsp; &nbsp;由于MySQL从5.7开始不允许首次安装后，使用空密码进行登录，系统会随机生成一个密码以供管理员首次登录使用，这个密码记录在/var/log/mysqld.log文件中，使用下面的命令可以查看此密码</p><pre><code >cat /var/log/mysqld.log|grep \'A temporary password\'\n\nA temporary password is generated for root@localhost: bkv,dy,)o7Ss</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;最后一行冒号后面的部分bkv,dy,)o7Ss就是初始密码。</p><h5 style=\"line-height: 3;\"><strong>8、密码登录MySQL</strong></h5><pre><code >mysql -u root -p</code></pre><h5 style=\"line-height: 3;\">9、更改默认密码</h5><pre><code >alter user \'root\'@\'localhost\' identified by \'your_password\';</code></pre><h5 style=\"line-height: 3;\"><strong>10、开启mysql的远程访问</strong></h5><p style=\"line-height: 3;\"> &nbsp; &nbsp;执行以下命令开启远程访问限制（注意：下面命令开启的IP是 192.168.19.128，如要开启所有的，用%代替IP）</p><pre><code >grant all privileges on *.* to \'root\'@\'192.168.0.1\' identified by \'password\' with grant option;\nmysql&gt; flush privileges;</code></pre><h5 style=\"line-height: 3;\">11、MySQL退出</h5><pre><code >exit\nquit\n\\q</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;解决：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;①、解决SELECT list is not in GROUP BY clause and contains nonaggregated column错误；在使用GROUP BY对Mysql的数据表进行查询时如果出现以上错误</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;解决方法1：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;查询mysql 相关mode</p><pre><code >select @@global.sql_mode;</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;可以看到模式中包含了ONLY_FULL_GROUP_BY，只要没有这个配置即可。我的Mysql版本是5.7.23，默认是带了ONLY_FULL_GROUP_BY模式。</p><pre><code >set @@global.sql_mode=\'STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION\';</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;解决方法2：打开mysql配置文件：my.cnf，直接选择打开mysql配置文件，然后在最底部添加</p><p>sql_mode=STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION </p><p style=\"line-height: 3;\"> &nbsp; &nbsp;重启mysql即可</p>',0,5,0,0,1754781241,1756217355,NULL),(10,4,'CentOS中Mysql tar.gz安装与配置','CentOS中Mysql tar.gz安装与配置','CentOS中Mysql tar.gz安装与配置','/adminapi/uploads/image/20250810/2b8c769e-c93c-4661-8472-fa7925854a5b.png','Amusing编程喵','<p style=\"line-height: 3;\"><strong>1.安装mysql之前需要确保系统中有libaio依赖，使用如下命令：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">yum search libaio</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">yum install libaio</span></p><p style=\"line-height: 3;\"><strong>2.进入centos终端操作界面，使用wget命令下载mysql5.7 64位安装文件：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">wget -c https://cdn.mysql.com//Downloads/MySQL-5.7/mysql-5.7.18-linux-glibc2.5-x86_64.tar.gz</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;下载完成如图所示：</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/3a794af6-970a-47fc-9996-42b98ee67927.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"><strong>3.将mysql安装包解压到指定目录，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">tar -zxvf mysql-5.7.18-linux-glibc2.5-x86_64.tar.gz -C /usr/local</span></p><p style=\"line-height: 3;\"><strong>4.进入/usr/local目录：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">cd /usr/local</span></p><p style=\"line-height: 3;\"><strong>5.为mysql安装目录创建软链接:</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">ln -s mysql-5.7.18-linux-glibc2.5-x86_64 mysql</span></p><p style=\"line-height: 3;\"><strong>6.为centos添加mysql用户组和mysql用户(-s /bin/false参数指定mysql用户仅拥有所有权，而没有登录权限):</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">groupadd mysql</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">useradd -r -g mysql -s /bin/false mysql</span></p><p style=\"line-height: 3;\"><strong>7.进入安装mysql软件的目录，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">cd /usr/local/mysql</span></p><p style=\"line-height: 3;\"><strong>8.修改当前目录拥有者为新建的mysql用户，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">chown -R mysql:mysql ./</span></p><p style=\"line-height: 3;\"><strong>9.安装mysql，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">./bin/mysqld --user=mysql --basedir=/usr/local/mysql --datadir=/usr/local/mysql/data --initialize</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;安装完成，出现如下信息，将随机生成的登录密码记录下来：</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/eec84a33-a2b8-4b2e-bbd5-7cd60d9a7f9b.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;问题解决：</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/5646bc72-7b95-4a47-a762-bfd01997e276.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;提示缺少libnuma.so.1这个文件，可能是因为系统是64位的，系统没有64位的这个so库，可以通过安装 yum&nbsp;install&nbsp;-y&nbsp;libaio来解决这个问题</p><p style=\"line-height: 3;\">10.开启mysql服务，命令如下：</p><p style=\"line-height: 3;\"> &nbsp; <span style=\"background-color: rgb(191, 191, 191);\"> ./support-files/mysql.server start</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;问题解决：</p><p style=\"line-height: 3;\">&nbsp; &nbsp; &nbsp;①、</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/62c0f523-ebd3-45fb-a402-c7950a495c21.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;没有/var/log/mariadb/mariadb.log这个路径,那我们就创建, 并给mysql用户授权即可</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">mkdir /var/log/mariadb </span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">touch /var/log/mariadb/mariadb.log </span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">chown -R mysql:mysql &nbsp;/var/log/mariadb/</span></p><p style=\"line-height: 3;\">&nbsp; &nbsp; &nbsp;②、</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/86500508-a286-4999-ae6c-9a59d02685ec.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;配置的问题，检查：</p><p style=\"line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/e99a7a7f-d7a4-4c4d-80bf-1abe270eb6b1.png\" alt=\"\" data-href=\"\" style=\"\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;③、如果开启mysql服务失败，报什么路径找不到，那是因为mysql启动时，会读mysql的配置文件/etc/my.cnf，因为里面的初始路径不对</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;修改内容如下，datadir和socket都修改成mysql的安装目录下，增加[client]板块，用于命令行连接mysql数据库</p><pre><code >    [mysqld]\n    port=3306\n    datadir=/usr/local/mysql/data\n    socket=/usr/local/mysql/mysql.sock\n    user=mysql\n\n    max_connections=151\n    federated\n\n    # Disabling symbolic-links is recommended to prevent assorted security risks\n    symbolic-links=0\n\n    [mysqld_safe]\n    log-error=/var/log/mysqld.log\n    pid-file=/var/run/mysqld/mysqld.pid\n\n    #指定客户端连接mysql时的socket通信文件路径\n    # 解决tmp/mysql.sock 错误\n    [client]\n    socket=/usr/local/mysql/mysql.sock</code></pre><p style=\"line-height: 3;\"><strong>11.将mysql进程放入系统进程中，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">cp support-files/mysql.server /etc/init.d/mysqld</span></p><p style=\"line-height: 3;\"><strong>12.重新启动mysql服务，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">service mysqld restart</span></p><p style=\"line-height: 3;\"><strong>13.使用随机密码登录mysql数据库，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">mysql -u root -p</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;等待系统提示，输入随机密码，即可登录</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;问题：</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/5e7072d0-0c1c-437b-b71d-c51725e5d84f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\">&nbsp; &nbsp; &nbsp;配置环境变量：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">export PATH=$PATH:/usr/local/mysql/bin</span></p><p style=\"line-height: 3;\"><strong>14.进入mysql操作行，为root用户设置新密码（小编设为rootroot）：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(140, 140, 140);\">alter user \'root\'@\'localhost\' identified by \'rootroot\';</span></p><p style=\"line-height: 3;\"><strong>15.设置允许远程连接数据库，命令如下：</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(140, 140, 140);\">update user set user.Host=\'%\' where user.User=\'root\';</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;问题解决：</p><p style=\"text-align: center; line-height: 3;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250810/213cfebd-719b-4688-bb52-47637e7c0bf1.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;在操作出现no database selected错误时，指数据库不存在，或者没有使用use 数据库名</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;解决办法：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;1、检查您的输入数据名是否正确或use 数据库名</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;<span style=\"background-color: rgb(191, 191, 191);\">use mysql; //Mysql 换您的数据库名</span></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;2.刷新权限，命令如下：</p><p style=\"line-height: 3;\"> &nbsp; <span style=\"background-color: rgb(191, 191, 191);\"> flush privileges;</span></p>',0,2,0,0,1754782918,1754972951,NULL),(11,4,'CentOS环境下安装Telnet服务','CentOS环境下安装Telnet服务','CentOS环境下安装Telnet服务','/adminapi/uploads/image/20250811/c7591a9f-431a-48b1-a331-e73ea8bce6e4.jpg','Amusing编程喵','<p><span style=\"color: rgb(66, 144, 247);\"><strong>1、检查是否已经安装</strong></span></p><pre><code >rpm -qa telnet-server\nrpm -qa xinetd</code></pre><p style=\"text-align: center; line-height: 1;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/d52ddddc-f661-484b-93e4-e479b235cb81.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"color: rgb(66, 144, 247);\"><strong>2、安装</strong></span></p><pre><code >yum -y install telnet\nyum -y install xinetd</code></pre><p><span style=\"color: rgb(66, 144, 247);\"><strong>3、启动服务</strong></span></p><pre><code >systemctl start xinetd.service        启动xinetd服务\nsystemctl enable xinetd.service       xinetd开机自启动\nsystemctl start telnet.socket         启动telnet服务\nsystemctl enable telnet.socket        telnet服务开机自启</code></pre><p><span style=\"color: rgb(66, 144, 247);\"><strong>4、进行telnet端口测试</strong></span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/67b1573c-419d-43be-b4d0-01fc61a4f414.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p>',0,1,0,0,1754919819,1754972949,NULL),(12,4,'CentOS安装RabbitMQ','CentOS安装RabbitMQ','CentOS安装RabbitMQ','/adminapi/uploads/image/20250811/cb2327d7-9b95-4a35-848b-a5ac3da1681b.png','Amusing编程喵','<h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">一、下载安装包</span></h2><p style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; RabbitMQ和Erlang的版本对应关系</span></p><p style=\"text-align: center; line-height: 1.5;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/7b61ff81-ab0c-4306-a7f2-00b0e45dbb3f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center; line-height: 1.5;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/049b7da4-2ee8-42ab-a3d5-3a418bb485a9.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 1.5;\"><strong>二、下载和安装Erlang</strong></p><p style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 下载Erlang，可以去github或gitcode</span></p><p style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\"><code> https://github.com/rabbitmq/erlang-rpm/releases https://gitcode.net/mirrors/rabbitmq/erlang-rpm?utm_source=csdn_github_accelerator </code></span></p><p style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;本地安装Erlang</span></p><pre><code >yum localinstall erlang-23.3.3-1.el7.x86_64.rpm\n安装socat\nsudo yum install -y socat\n</code></pre><p><strong>三、下载和安装RabbitMQ</strong></p><pre><code >下载RabbitMQ，可以去官网或github\n\nhttps://www.rabbitmq.com/download.html\n\nhttps://github.com/rabbitmq/rabbitmq-server/releases\n\n安装RabbitMQ\nyum localinstall rabbitmq-server-3.8.15-1.el7.noarch.rpm\n</code></pre><h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">四、运行RabbitMQ</span></h2><pre><code >启动RabbitMQ服务\nsudo systemctl start rabbitmq-server\n查看状态\nsudo systemctl status rabbitmq-server\n设置为开机启动\nsudo systemctl enable rabbitmq-server\n\n停止服务\nsudo systemctl stop rabbitmq-server\n\n查看相关进程\nps -ef |grep rabbitmq\n</code></pre><h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">五、配置防火墙</span></h2><pre><code >打开防火墙端口\nfirewall-cmd --zone=public --permanent --add-port=4369/tcp\nfirewall-cmd --zone=public --permanent --add-port=25672/tcp\nfirewall-cmd --zone=public --permanent --add-port=5671-5672/tcp\nfirewall-cmd --zone=public --permanent --add-port=15672/tcp\nfirewall-cmd --zone=public --permanent --add-port=61613-61614/tcp\nfirewall-cmd --zone=public --permanent --add-port=1883/tcp\nfirewall-cmd --zone=public --permanent --add-port=8883/tcp\n\n将防火墙配置重新载入：\nfirewall-cmd --reload\n</code></pre><h2 style=\"line-height: 1.5;\"> <span style=\"font-size: 16px;\">六、开启Web管理插件</span></h2><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;此时还不能通过web访问服务器的rabbitmq，为了实现这一功能。我们需要开启web管理插件。</span></p><pre><code >开启插件\nrabbitmq-plugins enable rabbitmq_management\n\n添加用户\nrabbitmqctl add_user admin admin\n\n为用户分配操作权限\nrabbitmqctl set_user_tags admin administrator\n为用户分配资源权限\nrabbitmqctl set_permissions -p / admin \".*\" \".*\" \".*\"\n<span style=\"font-size: 16px;\"> 然后就可以，在15672端口上登录管理界面了，地址：http://Your_Server_IP:15672/</span></code></pre><p><br></p>',0,0,0,0,1754920172,1754972948,NULL),(13,4,'CentOS安装 Sentinel','CentOS安装 Sentinel','CentOS安装 Sentinel','/adminapi/uploads/image/20250811/08d09ca6-e496-4ca8-9769-12a8b7fc2eef.png','Amusing编程喵','<p>1、下载Sentinel发布版本，地址<a href=\"https://links.jianshu.com/go?to=https%3A%2F%2Fgithub.com%2Falibaba%2FSentinel%2Freleases\" target=\"\">https://github.com/alibaba/Sentinel/releases</a></p><p>2、将下载的jar包sentinel-dashboard-1.8.0.jar上传到Linux服务器，Sentinel 是一个标准的 Spring Boot 应用，以 Spring Boot 的方式运行 jar 包即可，执行启动命令</p><pre><code >nohup java -Dserver.port=8086 -Dproject.name=sentinel-dashboard -jar sentinel-dashboard-1.8.0.jar &gt;/dev/null &\n\n忽略输入重定向错误到标准输出端 问题解决：\nnohup java -Dserver.port=10008 -Dproject.name=sentinel-dashboard -jar sentinel-dashboard-1.8.6.jar &gt;/dev/null 2&gt;&1 &\n</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/b66a57af-6906-40f8-aa09-a0758dfbf617.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p>',0,0,0,0,1754920370,1754972946,NULL),(14,5,'CentOS安装Nacos','CentOS安装Nacos','CentOS安装Nacos','/adminapi/uploads/image/20250811/912fb0e3-53e4-4e2c-bc4a-c5fbab872c15.jpg','Amusing编程喵','<p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/c3904a38-b32f-4532-b6f2-e316e31990f4.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/8d07ea8b-eb5c-4e80-b471-13433dcb9f7b.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/b407baa7-0ab7-4e94-a72a-63ab4045bf12.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"/></p>',0,0,0,0,1754920638,1754972943,NULL),(15,4,'CentOS中Java tar.gz安装与配置','CentOS中Java tar.gz安装与配置','CentOS中Java tar.gz安装与配置','/adminapi/uploads/image/20250811/13010917-e9ea-4a6a-92a6-ad19d9af8cae.jpeg','Amusing编程喵','<p><span style=\"color: rgb(66, 144, 247);\"><strong>一、tar.gz安装</strong></span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、下载JDK</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 下载地址：http://www.oracle.com/technetwork/java/javase/downloads/jdk8-downloads-2133151.html。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 测试文件：jdk-8u191-linux-x64.tar.gz</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、通过ftp工具将文件上传到CentOS主机上</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、进入安装目录</span></p><pre><code >cd /usr/local/</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4、解压安装文件到当前目录</span></p><pre><code >tar -zxvf /var/ftp/pub/jdk-8u191-linux-x64.tar.gz</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/19c5541a-92c8-4181-acc5-83a805dfccab.png\" alt=\"\" data-href=\"\" style=\"\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;5、添加环境变量</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 修改/etc/profile文件，在文件结尾添加配置信息</span></p><pre><code >export JAVA_HOME=/usr/local/jdk1.8.0_191\nexport CLASSPATH=$JAVA_HOME/lib:$JRE_HOME/lib:\nexport PATH=$JAVA_HOME/bin:$PATH\nvi /etc/profile\n执行source /etc/profile命令让配置生效\nsource /etc/profile\n</code></pre><p style=\"text-align: center;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;</span><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/76cd2a56-1bd6-4305-8409-2b65560578b8.png\" alt=\"\" data-href=\"\" style=\"\"><span style=\"font-size: 16px;\"> </span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;这种方式添加的环境变量对所有登录用户有效（如果.sh程序没有特别处理，一般是获取不到这个环境变量信息）</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;6、执行命令查看jdk版本信息</span></p><pre><code >java -version</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/d443bac1-c368-46fc-931b-fb953e41c653.png\" alt=\"\" data-href=\"\" style=\"\"></p><p><span style=\"color: rgb(66, 144, 247);\"><strong>二、yum安装</strong></span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、查看yum包含的jdk版本</span></p><pre><code >[root@suhw ~]# yum search java</code></pre><p style=\"line-height: 2;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 2、安装JDK</span></p><pre><code >[root@suhw ~]# yum install java-1.8.0-openjdk-devel.x86_64</code></pre><p style=\"line-height: 2;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 3、环境变量配置</span></p><pre><code >将以下三行内容写入/etc/profile中，JAVA_HOME以实际为准\nexport JAVA_HOME=/usr/lib/jvm/java-1.8.0-openjdk-1.8.0.252.b09-2.el7_8.x86_64\nexport CLASSPATH=.:$JAVA_HOME/jre/lib/rt.jar:$JAVA_HOME/lib/dt.jar:$JAVA_HOME/lib/tools.jar\nexport PATH=$PATH:$JAVA_HOME/bin</code></pre><p> &nbsp; &nbsp;4、安装校验</p><pre><code >[root@suhw ~]# source /etc/profile\n[root@suhw ~]# java -version\nopenjdk version \"1.8.0_252\"\nOpenJDK Runtime Environment (build 1.8.0_252-b09)\nOpenJDK 64-Bit Server VM (build 25.252-b09, mixed mode)</code></pre><p><br></p><p><br></p><p><br></p>',0,4,0,0,1754921092,1756217357,NULL),(16,4,'CentOS安装Tomcat','CentOS安装Tomcat','CentOS安装Tomcat','/adminapi/uploads/image/20250811/c86f91a2-d0d4-429a-9c52-2b19229a30f4.png','Amusing编程喵','<p style=\"line-height: 3;\"><span style=\"color: rgb(66, 144, 247);\"><strong>一、wget安装</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、安装Tomcat</span></p><pre><code >下载：\n[root@suhw ~]# cd /usr/local/\n[root@suhw local]# wget http://mirrors.hust.edu.cn/apache/tomcat/tomcat-8/v8.5.55/bin/apache-tomcat-8.5.55.tar.gz\n\n解压：\n[root@suhw local]# tar -zxvf apache-tomcat-8.5.55.tar.gz\n# 修改名称\n[root@suhw local]# mv apache-tomcat-8.5.55 tomcat</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、启动</span></p><pre><code >[root@suhw ~]# /usr/local/tomcat/bin/startup.sh\nUsing CATALINA_BASE:   /usr/local/tomcat\nUsing CATALINA_HOME:   /usr/local/tomcat\nUsing CATALINA_TMPDIR: /usr/local/tomcat/temp\nUsing JRE_HOME:        /usr\nUsing CLASSPATH:       /usr/local/tomcat/bin/bootstrap.jar:/usr/local/tomcat/bin/tomcat-juli.jar\nTomcat started.\n </code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、关闭</span></p><pre><code >[root@suhw ~]# /usr/local/tomcat/bin/shutdown.sh\nUsing CATALINA_BASE:   /usr/local/tomcat\nUsing CATALINA_HOME:   /usr/local/tomcat\nUsing CATALINA_TMPDIR: /usr/local/tomcat/temp\nUsing JRE_HOME:        /usr\nUsing CLASSPATH:       /usr/local/tomcat/bin/bootstrap.jar:/usr/local/tomcat/bin/tomcat-juli.jar</code></pre><p style=\"line-height: 3;\"><span style=\"color: rgb(66, 144, 247);\"><strong>二、yum安装</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、查看安装包信息</span></p><pre><code >yum info tomcat</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、安装</span></p><pre><code > yum -y install tomcat</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、查看是否安装成功</span></p><pre><code > rpm -q tomcat\n 输出：\n tomcat-7.0.76-16.el7_9.noarch\n 表示安装成功。</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4、配置环境变量</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;tomcat 默认安装路径</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;/usr/share/tomcat/</span></p><pre><code >加入环境变量配置\n在 /etc/profile 配置文件中加入 Tomcat 环境变量:\n\nJAVA_HOME=/usr/lib/jvm/java\n\nPATH=$PATH:$JAVA_HOME/bin\n\nCLASSPATH=.:$JAVA_HOME/lib/dt.jar:$JAVA_HOME/lib/tools.jar\n\nCATALINA_BASE=/usr/share/tomcat\n\nCATALINA_HOME=/usr/share/tomcat\n\nexport JAVA_HOME PATH CLASSPATH CATALINA_BASE CATALINA_HOME\n\n使配置文件生效:\nsource /etc/profile\n </code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;5、查看是否生效</span></p><pre><code > echo $CATALINA_BASE\n echo $CATALINA_HOME\n  </code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;6、启动 tomcat</span></p><pre><code > systemctl start tomcat.service</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;7、查看是否启动</span></p><pre><code > systemctl status tomcat</code></pre><p><br></p>',0,4,0,0,1754921472,1756217358,NULL),(17,4,'CentOS中Nginx tar.gz安装与配置','CentOS中Nginx tar.gz安装与配置','CentOS中Nginx tar.gz安装与配置','/adminapi/uploads/image/20250811/fafaee52-7e73-4385-8c9a-58b858b5c0a6.jpeg','Amusing编程喵','<p style=\"line-height: 3;\"><strong>1、gcc 安装</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;安装 nginx 需要先将官网下载的源码进行编译，编译依赖 gcc 环境，如果没有 gcc 环境，则需要安装：</p><pre><code >yum install gcc-c++</code></pre><p style=\"line-height: 3;\"><strong>2、CRE pcre-devel 安装</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;PCRE(Perl Compatible Regular Expressions) 是一个Perl库，包括 perl 兼容的正则表达式库。nginx 的 http 模块使用 pcre 来解析正则表达式，所以需要在 linux 上安装 pcre 库，pcre-devel 是使用 pcre 开发的一个二次开发库。nginx也需要此库。命令：</p><pre><code >yum install -y pcre pcre-devel</code></pre><p style=\"line-height: 3;\"><strong>3、zlib 安装</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;zlib 库提供了很多种压缩和解压缩的方式， nginx 使用 zlib 对 http 包的内容进行 gzip ，所以需要在 Centos 上安装 zlib 库。</p><pre><code >yum install -y zlib zlib-devel\n</code></pre><p style=\"line-height: 3;\"><strong>4、OpenSSL 安装</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;OpenSSL 是一个强大的安全套接字层密码库，囊括主要的密码算法、常用的密钥和证书封装管理功能及 SSL 协议，并提供丰富的应用程序供测试或其它目的使用。</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;nginx 不仅支持 http 协议，还支持 https（即在ssl协议上传输http），所以需要在 Centos 安装 OpenSSL 库。</p><pre><code >yum install -y openssl openssl-devel</code></pre><p style=\"line-height: 3;\"><strong>5、Nginx下载</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;使用wget命令下载Nginx（没有wget就需要安装一下yum -y install wget）版本可以自己选择</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;wget -c <a href=\"https://nginx.org/download/nginx-1.12.0.tar.gz\" target=\"\">https://nginx.org/download/nginx-1.12.0.tar.gz</a></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;或官网下载</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;直接下载.tar.gz安装包，地址：https://nginx.org/en/download.html</p><p style=\"line-height: 3;\"><strong>6、解压</strong></p><pre><code >tar -zxvf nginx-1.12.0.tar.gz\ncd nginx-1.12.0</code></pre><p style=\"line-height: 3;\"><strong>7、配置</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp; 其实在 nginx-1.12.0 版本中你就不需要去配置相关东西，默认就可以了。当然，如果你要自己配置目录也是可以的。</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; 1.使用默认配置</p><pre><code >./configure\n\n// 安装stream，用于接口转发\n./configure --with-stream\n\n//关键所在：因为默认会安装在/usr/local/nginx，所以此处需要指明目的文件夹 \n./configure --prefix=/usr/mydir/nginx\n</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;2、支持HTTPS</p><pre><code >./configure --prefix=/usr/local/nginx --with-http_ssl_module\n\n./configure --prefix=/usr/local/nginx --with-http_stub_status_module --with-http_ssl_module --with-stream</code></pre><p style=\"line-height: 3;\"><strong>8、编译安装</strong></p><pre><code >make\nmake install</code></pre><p style=\"line-height: 3;\"><strong>9、启动、停止</strong></p><p style=\"line-height: 3;\"> &nbsp; &nbsp;查找安装路径：</p><pre><code >whereis nginx</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;命令启动，停止，等。。。。</p><pre><code >./nginx --启动\n./nginx -s stop --停止\n./nginx -s quit\n./nginx -s reload</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;查看是否运行</p><pre><code >ps -A | grep nginx</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;错误解决：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; ①、启动报错</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; nginx: [emerg] the \"http2\" parameter requires ngx_http_v2_module in /usr/local/nginx/conf/nginx.conf:28</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; 提示http2需要ngx_http_v2_module模块的支持，我们知道在安装nginx在编译时添加了好多自己需要的模块，这里提示需要模块的支持，那编译时肯定没加这个模块，那只好添加上这个模块重新编译</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; #cd到nginx的安装包目录下面对软件进行相关配置并重新编译</p><pre><code >./configure --user=nginx --group=nginx --prefix=/usr/local/nginx --with-http_addition_module --with-http_flv_module --with-http_gzip_static_module --with-http_realip_module --with-http_ssl_module --with-http_stub_status_module --with-http_sub_module --with-http_dav_module --with-http_v2_module #--with-http_v2_module</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;这便是我们添加的上面提示http2需要的支持模块</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; (1)切换到源码包：</p><pre><code >cd /root/nginx-1.13.6</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;(2)配置信息：</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;(3)配置完成后，运行make进行编译，千万不要进行make install，否则就是覆盖安装。</p><pre><code >make</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;(4)然后备份原有已经安装好的nginx</p><pre><code >cp /usr/local/nginx/sbin/nginx /usr/local/nginx/sbin/nginx.bak</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;(5)关闭Nginx</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;(6)将刚刚编译好的nginx覆盖掉原有的nginx</p><pre><code >cp ./objs/nginx /usr/local/nginx/sbin/</code></pre><p style=\"line-height: 3;\"> &nbsp; &nbsp;(5)启动Nginx</p><p style=\"line-height: 3;\"> &nbsp; &nbsp;②、[emerg] getpwnam(\"nginx\") failed</p><p style=\"line-height: 3;\"> &nbsp; &nbsp; 没有安装nginx用户导致的无法启动</p><pre><code >useradd -s /sbin/nologin -M nginx\nid nginx</code></pre><p><br></p>',0,1,0,0,1754924638,1756217361,NULL),(18,4,'CentOS部署kkFileView部署（直接下载）','CentOS部署kkFileView部署（直接下载）','CentOS部署kkFileView部署（直接下载）','/adminapi/uploads/image/20250811/88a2ccb8-73a3-49be-b25c-20cefa6fecd1.png','Amusing编程喵','<h3><span style=\"font-size: 16px;\">一、安装 LiberOffice</span></h3><pre><code >wget https://kkfileview.keking.cn/LibreOffice_7.1.4_Linux_x86-64_rpm.tar.gz\ntar -zxvf LibreOffice_7.1.4_Linux_x86-64_rpm.tar.gz\ncd LibreOffice_7.1.4.2_Linux_x86-64_rpm/RPMS\nyum install -y *.rpm\n</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;注：安装过程如下，office组件较大请耐心等待 </span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/748d6cdd-35c2-4a89-8818-274851c6ed06.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h3><span style=\"font-size: 16px;\">二、验证office组件</span></h3><pre><code >cd /opt/libreoffice7.1/program\n./soffice --version\n\n# // 注册soffice命令, 修改环境变量文件\n# vim /etc/profile\n# // 添加下面内容\n# export PATH=$PATH:/opt/libreoffice7.1/program\n# // 执行如下命令使环境变量生效\n# source /etc/profile\n# soffice --version，成功返回版本号即表示已注册</code></pre><h3> <span style=\"font-size: 16px;\">三、安装kkfileview</span></h3><pre><code >wget https://kkfileview.keking.cn/kkFileView-4.1.0.tar.gz\ntar -zxvf kkFileView-4.1.0.tar.gz</code></pre><h3> <span style=\"font-size: 16px;\">四、修改kkfileview配置参数 </span></h3><pre><code >cd kkFileView-4.1.0/config/application.properties\n\n# 说明:加粗标识具体情况修改\nserver.port = ${KK_SERVER_PORT:8081}\n#文件资源路径\nfile.dir = ${KK_FILE_DIR:/data/app/kkfileview/kkFileView-4.0.0/temp}\n###################### office-plugin #####################\n##office服务的进程数，默认开启两个进程\noffice.plugin.server.ports = 2021,2022\n#office组件home路径\noffice.home = ${KK_OFFICE_HOME:/opt/libreoffice7.1}</code></pre><h3> <span style=\"font-size: 16px;\">五、运行启动程序</span></h3><pre><code >cd kkfileview/bin/\n./startup.sh | ./showlog.sh</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/1296111e-19ab-4123-9fe7-fa3556e5e7c5.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h3><span style=\"font-size: 16px;\">六、访问文档预览服务</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;浏览器打开 http://{your-kkfileview-service-ip:port}/index</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/d03b22f1-10c4-460d-85c6-a0539960a8a8.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/c9c4f5ef-6b53-47dd-baed-86a21e88a680.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;nginx代理：</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、修改配置文件</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/b975cfda-503a-41d6-8b09-a6b5d86c7e82.png\" alt=\"\" data-href=\"\" style=\"\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、修改nginx</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/5cc2bdbb-280c-45d9-9299-a42003bd6f83.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、测试</span></p><pre><code >https://base64.us/\nhttps://www.sojson.com/encodeurl.html\n</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;如果文件不可用预览，可能base64加密原因导致</span></p>',0,0,0,0,1754926477,1754972938,NULL),(19,4,'CentOS中Redis rpm安装与配置','CentOS中Redis rpm安装与配置','CentOS中Redis rpm安装与配置','/adminapi/uploads/image/20250811/a14c7186-89f7-4518-911a-74c3a4c48904.jpg','Amusing编程喵','<p style=\"line-height: 3;\"><strong>1、下载redis安装包</strong></p><pre><code >wget http://download.redis.io/releases/redis-4.0.6.tar.gz</code></pre><p style=\"line-height: 3;\"><strong>2、解压压缩包</strong></p><pre><code >tar -zxvf redis-4.0.6.tar.gz</code></pre><p style=\"line-height: 3;\"><strong>3、yum安装gcc依赖</strong></p><pre><code >yum install gcc</code></pre><p style=\"line-height: 3;\"><strong>3、yum安装gcc依赖</strong></p><pre><code >yum install gcc</code></pre><p style=\"line-height: 3;\"><strong>4、跳转到redis解压目录下</strong></p><pre><code >cd redis-4.0.6</code></pre><p style=\"line-height: 3;\"><strong>5、编译安装</strong></p><pre><code >make MALLOC=libc\n将/usr/local/redis-4.0.6/src目录下的文件加到/usr/local/bin目录\ncd src && make install</code></pre><p style=\"line-height: 3;\"><strong>6、启动redis的三种方式</strong></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 先切换到redis src目录下</span></p><h3 style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp; ①、直接启动redis</span></h3><pre><code >./redis-server</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;redis启动成功，但是这种启动方式需要一直打开窗口，不能进行其他操作，不太方便。</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;按 ctrl + c可以关闭窗口。</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"><strong> &nbsp; &nbsp;②、以后台进程方式启动redis</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;第一步：修改redis.conf文件，将daemonize no修改为daemonize yes</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;第二步：指定redis.conf文件启动</span></p><pre><code >./redis-server /usr/local/redis-4.0.6/redis.conf</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;第三步：关闭redis进程</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;首先使用ps -aux | grep redis查看redis进程</span></p><pre><code >ps -aux | grep redis</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;使用kill命令杀死进程</span></p><pre><code >kill 18714</code></pre><h3 style=\"line-height: 3;\"><span style=\"font-size: 16px;\">3、设置redis开机自启动</span></h3><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、在/etc目录下新建redis目录</span></p><pre><code >mkdir redis</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、将/usr/local/redis-4.0.6/redis.conf 文件复制一份到/etc/redis目录下，并命名为6379.conf </span></p><pre><code >cp /usr/local/redis-4.0.6/redis.conf /etc/redis/6379.conf</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、将redis的启动脚本复制一份放到/etc/init.d目录下</span></p><pre><code >cp /usr/local/redis-4.0.6/utils/redis_init_script /etc/init.d/redisd</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4、设置redis开机自启动</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;先切换到/etc/init.d目录下，然后执行自启命令</span></p><pre><code >chkconfig redisd on</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;service redisd does not support chkconfig，看结果是redisd不支持chkconfig</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;解决方法：</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;使用vim编辑redisd文件，在第一行加入如下两行注释，保存退出</span></p><pre><code ># chkconfig: 2345 90 10\n# description: Redis is a persistent key-value database</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;注释的意思是，redis服务必须在运行级2，3，4，5下被启动或关闭，启动的优先级是90，关闭的优先级是10。</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;再次执行开机自启命令，成功</span></p><pre><code >chkconfig redisd on</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;现在可以直接已服务的形式启动和关闭redis</span></p><pre><code >启动：\nservice redisd start　\n关闭：\nservice redisd stop\nredis-cli SHUTDOWN</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改密码：</span></p><pre><code >vim redis.conf</code></pre><p style=\"text-align: center;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;</span><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/4d418b3d-9d18-4c08-9c9c-7bf15849ac6d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改后，重启redis</span></p>',0,2,0,0,1754927126,1756217362,NULL),(20,4,'CentOS安装Docker的详细安装步骤','CentOS安装Docker的详细安装步骤','CentOS安装Docker的详细安装步骤','/adminapi/uploads/image/20250811/8e127ad5-a305-4ad9-b9ef-68cb7adb595e.jpeg','Amusing编程喵','<p style=\"line-height: 3;\"><strong>1.卸载旧的版本</strong></p><pre><code class=\"language-bash\">sudo yum remove docker \\\n                  docker-client \\\n                  docker-client-latest \\\n                  docker-common \\\n                  docker-latest \\\n                  docker-latest-logrotate \\\n                  docker-logrotate \\\n                  docker-engine          </code></pre><p style=\"line-height: 3;\"><strong>2.需要安装包</strong></p><pre><code class=\"language-bash\">sudo yum install -y yum-utils</code></pre><p style=\"line-height: 3;\"><strong>3.设置镜像仓库</strong></p><pre><code class=\"language-bash\">官方镜像：（比较慢，不推荐）\nsudo yum-config-manager \\\n    --add-repo \\\n    https://download.docker.com/linux/centos/docker-ce.repo\n阿里镜像仓库 ：（推荐）\nsudo yum-config-manager \\\n    --add-repo \\\n    http://mirrors.aliyun.com/docker-ce/linux/centos/docker-ce.repo</code></pre><p style=\"line-height: 3;\"><strong>4.安装 docker</strong></p><pre><code class=\"language-bash\">安装前先更新yum软件包索引\nyum makecache fast\n\n安装docker-ce（社区版-免费的）\nsudo yum install docker-ce docker-ce-cli containerd.io</code></pre><p style=\"line-height: 3;\"><strong>5.启动docker</strong></p><pre><code class=\"language-bash\">sudo systemctl start docker</code></pre><p style=\"line-height: 3;\"><strong>6.如何判断是否成功安装docker 查看版本</strong></p><pre><code class=\"language-bash\">docker version</code></pre><p style=\"line-height: 3;\"><strong>7.查看镜像（是空的）</strong></p><pre><code class=\"language-bash\">docker images</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;因为使用阿里云镜像仓库，可以配置阿里云的镜像加速–速度更快（可选）</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1.搜索阿里云</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2.在阿里云里搜索 – 容器镜像服务</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.点击立即开通–镜像工具–镜像加速器–选择CentOS</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/18b3274f-d436-4aee-914d-ac3806932d02.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250811/3e314fe3-b217-46bb-9ab1-330785ee876d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;使用CentOS中的代码配置</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1.创建一个目录</span></p><pre><code class=\"language-bash\">sudo mkdir -p /etc/docker</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2.编辑配置文件（通过修改daemon配置文件/etc/docker/daemon.json来使用加速器）</span></p><pre><code class=\"language-bash\">sudo tee /etc/docker/daemon.json &lt;&lt;-\'EOF\'\n {\n   \"registry-mirrors\": [\"xxxx替换自己的加速地址\"]\n }\n EOF</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.重启服务</span></p><pre><code class=\"language-bash\">sudo systemctl daemon-reload</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4.重启docker</span></p><pre><code class=\"language-bash\">sudo systemctl restart docker</code></pre><p style=\"line-height: 3;\"><strong>8.卸载docker</strong></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1.卸载依赖</span></p><pre><code class=\"language-bash\">sudo yum remove docker-ce docker-ce-cli containerd.io</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2.删除文件夹</span></p><pre><code class=\"language-bash\">sudo rm -rf /var/lib/docker\nsudo rm -rf /var/lib/containerd</code></pre><h1 style=\"line-height: 3;\"><span style=\"font-size: 16px;\">补充：docker安装时候指定主目录（到一个大点的磁盘）</span></h1><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;查看默认主目录：</span></p><pre><code class=\"language-bash\">[root@VM-0-2-centos srv]# sudo docker info | grep \"Docker Root Dir\"\nDocker Root Dir: /var/lib/docker</code></pre><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改docker的默认配置文件(/etc/docker)：daemon.json(如果没有则新建一个即可)</span></p><p style=\"line-height: 3;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;添加\"graph\": \"/srv/docker\"的键值对，值为你磁盘的目录（自己新建一下即可），一般为数据盘/data下。</span></p><pre><code class=\"language-bash\">[root@VM-0-2-centos docker]# vim daemon.json\n[root@VM-0-2-centos docker]# cat daemon.json\n{\n    \"graph\": \"/data/docker\"\n}\n[root@VM-0-2-centos docker]# sudo docker info | grep \"Docker Root Dir\"\nDocker Root Dir: /data/docker\n注意：如果graph不好使，启动docker启动不起来，则尝试用data-home参数设置：\n{\n    \"data-root\": \"/data/docker\"\n}</code></pre><p><br></p>',0,7,0,0,1754927608,1756217363,NULL),(21,4,'CentOS安装Maven','CentOS安装Maven','CentOS安装Maven','/adminapi/uploads/image/20250813/d039cd00-6bac-4a7f-8353-609677d28722.jpg','Amusing编程喵','<p><strong>一、tar.gz安装</strong></p><p style=\"text-align: left;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/41c0ec65-6882-4f14-a122-bb5ebd672ce4.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: left;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/496c37b9-16bb-4604-a698-878163b4196f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><pre><code >tar -zxvf 安装包名 -C 解压路径</code></pre><p><span style=\"font-size: 16px;\">4、设置环境变量，编辑profile文件，执行以下命令</span></p><pre><code >vim /etc/profile</code></pre><p><span style=\"font-size: 16px;\">5、在此文件最后加入以下内容</span></p><pre><code >export MAVEN_HOME=/opt/apache-maven-3.5.4\nexport PATH=$PATH:$MAVEN_HOME/bin</code></pre><p><span style=\"font-size: 16px;\">6、执行以下命令刷新环境变量</span></p><pre><code >source /etc/profile</code></pre><p><span style=\"font-size: 16px;\">7、验证是否配置成功，执行以下命令</span></p><pre><code >mvn -version</code></pre><p><strong>二、wget安装</strong></p><pre><code ># 下载maven\nwget https://dlcdn.apache.org/maven/maven-3/3.8.5/binaries/apache-maven-3.8.5-bin.tar.gz\n# 解压\ntar -zxvf apache-maven-3.8.5-bin.tar.gz\nmv apache-maven-3.8.5 /usr/local/maven/\n# 配置环境变量\nvim /etc/profile\n\nMAVEN_HOME=/usr/local/maven\nPATH=${MAVEN_HOME}/bin:${PATH}\nexport PATH\n\n# 刷新\nsource /etc/profile\n\n# 查看\nmvn -v</code></pre><p><strong>三、Maven配置</strong></p><pre><code ># 替换maven源\nvim /usr/local/maven/conf/settings.xml\n\n# 找到&lt;mirrors&gt;&lt;/mirrors&gt;标签对,添加以下内容\n&lt;mirror&gt;\n   &lt;id&gt;alimaven&lt;/id&gt;\n    &lt;name&gt;aliyun maven&lt;/name&gt;\n    &lt;url&gt;http://maven.aliyun.com/nexus/content/groups/public/&lt;/url&gt;\n    &lt;mirrorOf&gt;central&lt;/mirrorOf&gt;\n    &lt;releases&gt;\n        &lt;enabled&gt;true&lt;/enabled&gt;\n        &lt;updatePolicy&gt;always&lt;/updatePolicy&gt;\n    &lt;/releases&gt;\n    &lt;snapshots&gt;\n        &lt;enabled&gt;true&lt;/enabled&gt;\n        &lt;updatePolicy&gt;always&lt;/updatePolicy&gt;\n    &lt;/snapshots&gt;\n&lt;/mirror&gt;\n\n# 指定下载源位置\n&lt;localRepository&gt;/usr/local/maven/repository&lt;/localRepository&gt;</code></pre><p><br></p>',0,0,0,0,1755091739,1755091739,NULL),(22,4,'Docker安装RabbitMQ','Docker安装RabbitMQ','Docker安装RabbitMQ','/adminapi/uploads/image/20250811/cb2327d7-9b95-4a35-848b-a5ac3da1681b.png','Amusing编程喵','<p><strong>1、使用docker查询RabbitMq的镜像</strong></p><pre><code >docker search rabbitmq</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/fdad0936-eeea-4495-81e1-9da3196a909d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>2、安装镜像</strong></p><p> 安装name为rabbitmq的这里是直接安装最新的，如果需要安装其他版本在rabbitmq后面跟上版本号即可</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/bbdfb915-3f07-404f-b3b7-1c7b17a113b0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>3、运行mq</strong></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/110ccc7f-c401-42cb-93c3-5f153a09da34.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >docker search rabbitmq\n\ndocker pull rabbitmq\n\ndocker run -d --hostname my-rabbit --name rabbit -p 15672:15672 -p 5673:5672 rabbitmq\ndocker run -d --name rabbitmq --privileged=true -p 15672:15672 -p 5673:5672 rabbitmq\n\ndocker run -d --name 容器名称 --hostname lucky --add-host lucky:192.168.1.2 --network host 镜像ID\n\ndocker exec -it 容器id /bin/bash\n\nrabbitmq-plugins enable rabbitmq_management\n\nexit退出容器目录</code></pre><p><br></p>',0,0,0,0,1755092109,1755092109,NULL),(23,4,'Docker安装Seata','Docker安装Seata','Docker安装Seata','/adminapi/uploads/image/20250813/09a5be59-0633-4d42-ad28-4e19f0fff6b7.png','Amusing编程喵','<p><strong>1、Seata镜像下载</strong></p><pre><code >docker pull seataio/seata-server:1.3.0</code></pre><p><strong>2、运行seata</strong></p><p><span style=\"font-size: 16px;\"> （1）不配置启动seata</span></p><pre><code >docker run -d --name seata-server -p 8091:8091 seataio/seata-server:1.4.0 <span style=\"font-size: 16px;\">   </span></code></pre><p><span style=\"font-size: 16px;\">（2）将配置文件拷贝出来</span></p><pre><code >docker cp seata-server:/seata-server/resources /home/docker/seata/config/</code></pre><p><span style=\"font-size: 16px;\">（3）编辑配置文件file.conf和registry.conf</span></p><p><span style=\"font-size: 16px;\">（4）挂载配置文件重新启动seata</span></p><pre><code ># 停止容器\ndocker stop seata-server\n# 删除容器\ndocker rm seata-server\n# 重新启动容器，这次是为了挂载外面的配置文件\n docker run -d \\\n        --name seata-server \\\n        -p 10007:10007 \\\n        -e SEATA_IP=39.98.108.121 \\\n        -e SEATA_PORT=10007 \\\n        -v /home/seata-1.3.0/resources:/seata-server/resources seataio/seata-server:1.3.0  </code></pre><p> </p><p><strong>3.问题解决</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、如果数据库无法连接，下面配置的是nacos，数据库配置从nacos去，而不是file.conf</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/660d5c40-6c6a-4d5c-8bbb-7a12d044057f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、springboot配置seata连接报错：can not register RM,err:can not connect to services-server.</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/80d36c52-58a5-4fb8-916c-78e6220135d9.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/e2996a06-740c-4281-980b-e999690bdd0f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;这两个地方必须一样。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;如果使用docker启动seata，需要启动端口，映射端口都一样</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/24c635cb-bfbe-4df1-a957-05e7f3300abf.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><br></p><p><br></p>',0,0,0,0,1755092558,1755092558,NULL),(24,4,'Docker搭建私人Maven仓库','Docker搭建私人Maven仓库','Docker搭建私人Maven仓库','/adminapi/uploads/image/20250813/d039cd00-6bac-4a7f-8353-609677d28722.jpg','Amusing编程喵','<p><strong>1、搜索镜像</strong></p><pre><code >docker search nexus</code></pre><p><strong>2、拉取镜像</strong></p><pre><code >docker pull sonatype/nexus3</code></pre><p><strong>3、创建挂载目录</strong></p><pre><code >mkdir /usr/local/work/maven</code></pre><p><strong>4、赋权限</strong></p><pre><code >chmod 777 /usr/local/work/maven</code></pre><p><strong>5、运行容器 因为我的docker还在运行其他容器,如果不添加内存限制的话,就会运行不起来</strong></p><pre><code >docker run -d -p 8081:8081 --name nexus -v /usr/local/work/maven:/var/nexus-data -e INSTALL4J_ADD_VM_PARAMS=\"-Xms256M -Xmx512M -XX:MaxDirectMemorySize=512M\" sonatype/nexus3</code></pre><p><strong>6、查看nexus启动情况日志</strong></p><pre><code >docker logs -f nexus</code></pre><p><br></p>',0,0,0,0,1755092849,1755092849,NULL),(25,4,'Docker安装 Jdk1.8','Docker安装 Jdk1.8','Docker安装 Jdk1.8','/adminapi/uploads/image/20250811/13010917-e9ea-4a6a-92a6-ad19d9af8cae.jpeg','Amusing编程喵','<p><strong>一、查找jdk</strong></p><pre><code >docker search jdk</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/efc5a1bc-c974-4898-aa7d-4dbb112c1768.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>二、下载 jdk</strong></p><pre><code >docker pull kdvolder/jdk8</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/57331457-13c0-4eae-8266-e362f9ea3526.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>三、查看是否下载成功</strong></p><pre><code >docker images</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/98669ffc-ef1a-490f-b8c3-4d58dbbe7a48.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>四、启动</strong></p><pre><code >docker run -di --name=jdk1.8 kdvolder/jdk8</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/5ae46087-254e-4504-885f-2bb86cafac9b.png\" alt=\"\" data-href=\"\" style=\"\"></p><p><strong>五、查看是否启动成功</strong></p><pre><code >docker ps</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/7e003198-f0d0-4494-957f-421c99b56c15.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p><strong>六、查看版本</strong></p><pre><code >docker exec -it jdk1.8 /bin/bash \njava -version</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/80ac0483-7559-4ee2-a72b-d733a1209521.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p>',0,0,0,0,1755094415,1755094415,NULL),(26,4,'Windows中DataxWeb安装部署及使用','Windows中DataxWeb安装部署及使用','Windows中DataxWeb安装部署及使用','/adminapi/uploads/image/20250813/b473f5f0-e2b6-4b46-9465-49428ab3eff0.jpg','Amusing编程喵','<p><span style=\"font-size: 16px;\"><strong>一、安装python环境</strong></span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;问题：python不是内部或外部命令，也不是可运行的程序或批处理文件</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;解决：右键我的电脑-&gt;属性-&gt;高级系统配置-&gt;点击高级一栏，在这里栏点开环境变量-&gt;在系统变量PATH加入python的安装路径即可，比如我的就是...\\Python3</span></p><p><strong>二、安装datax</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、直接下载DataX工具包</span></p><pre><code >   http://datax-opensource.oss-cn-hangzhou.aliyuncs.com/datax.tar.gz  </code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;解压datax.tar.gz就可以（然后配置文件指向bin）</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/cce68f24-cf21-44e1-b5d1-88aa06614c12.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><pre><code >下载后解压至本地某个目录，进入bin目录，即可运行同步作业：\n    ``` shell\n    $ cd  {YOUR_DATAX_HOME}/bin\n    $ python datax.py {YOUR_JOB.json}\n    ```\n自检脚本：\n    python {YOUR_DATAX_HOME}/bin/datax.py {YOUR_DATAX_HOME}/job/job.json</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、下载DataX源码，自己编译 </span></p><pre><code >下载DataX源码：\n https://github.com/alibaba/DataX\n\n``` shell\n$ git clone git@github.com:alibaba/DataX.git\n```\n(2)、通过maven打包：\n``` shell\n$ cd  {DataX_source_code_home}\n$ mvn -U clean package assembly:assembly -Dmaven.test.skip=true\n```\n打包成功，日志显示如下：\n```\n[INFO] BUILD SUCCESS\n[INFO] -----------------------------------------------------------------\n[INFO] Total time: 08:12 min\n[INFO] Finished at: 2015-12-13T16:26:48+08:00\n[INFO] Final Memory: 133M/960M\n[INFO] -----------------------------------------------------------------\n```\n打包成功后的DataX包位于 {DataX_source_code_home}/target/datax/datax/ ，结构如下：\n``` shell\n$ cd  {DataX_source_code_home}\n$ ls ./target/datax/datax/\nbin       conf      job       lib       log       log_perf   plugin    script    tmp\n```</code></pre><p><strong>三、DataxWeb安装</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 1、下载代码</span></p><pre><code >https://github.com/WeiYe-Jing/datax-web\nhttps://gitee.com/WeiYe-Jing/datax-web</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、导入数据库</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、修改配置文件</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/50d4e181-0d3a-4948-8c21-c84912375b2d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.1.修改datax_admin下resources/application.yml文件</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/708f2cfd-a9ae-4734-bba9-7b55dd0553f6.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.1.1修改数据源配置，目前仅支持mysql</span></p><pre><code >#数据源\ndatasource:\n  #    username: root\n  #password: root\n  #url: jdbc:mysql://localhost:3306/datax_web?serverTimezone=Asia/Shanghai&useLegacyDatetimeCode=false&useSSL=false&nullNamePatternMatchesAll=true&useUnicode=true&characterEncoding=UTF-8\n  \n  #数据库密码\n  password: ${DB_PASSWORD:root123}\n  #数据库账号\n  username: ${DB_USERNAME:root}\n  #数据库连接地址\n  url: jdbc:mysql://${DB_HOST:127.0.0.1}:${DB_PORT:3306}/${DB_DATABASE:datax_web}?serverTimezone=Asia/Shanghai&useLegacyDatetimeCode=false&useSSL=false&nullNamePatternMatchesAll=true&useUnicode=true&characterEncoding=UTF-8\n  driver-class-name: com.mysql.jdbc.Driver</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 3.1.2修改日志路径path</span></p><pre><code >logging:\n  #level:\n    #com.wugui.datax.admin.mapper: info\n    #path: ./data/applogs/admin\n  level:\n    com.wugui.datax.admin.mapper: error\n    path: ./data/applogs/admin</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.1.3修改邮件发送配置(不需要最后也把他写上，随便写个邮件，密码就行，不然启动报错)</span></p><pre><code ># datax-web email\n  mail:\n    host: smtp.qq.com\n    port: 25\n    #username: xxx@qq.com\n    #password: xxx\n    username: 123456@qq.com\n    password: 123456\n    properties:\n      mail:\n        smtp:\n          auth: true\n          starttls:\n            enable: true\n            required: true\n        socketFactory:\n          class: javax.net.ssl.SSLSocketFactory\n          </code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.2.修改datax_executor下resources/application.yml文件</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/75f90f7b-fdc3-4577-900a-ba14154668a9.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.2.1修改日志路径path</span></p><pre><code ># log config\nlogging:\n  config: classpath:logback.xml\n  path: ./data/applogs/executor/jobhandler\n  </code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3.2.2修改datax.job配置</span></p><pre><code >datax:\n  job:\n    admin:\n      ### datax-web admin address\n      addresses: http://127.0.0.1:8080\n    executor:\n      appname: datax-executor\n      ip:\n      port: 9999\n      ### job log path\n      logpath: ./data/applogs/executor/jobhandler\n      ### job log retention days\n      logretentiondays: 30\n  executor:\n    jsonpath: /Users/mac/data/applogs\n  pypath: /Users/mac/tools/datax/bin/datax.py\n  </code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;admin.addresses datax_admin部署地址，如调度中心集群部署存在多个地址则用逗号分隔，执行器将会使用该地址进行\"执行器心跳注册\"和\"任务结果回调\"；</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.appname 执行器AppName，每个执行器机器集群的唯一标示,执行器心跳注册分组依据；</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.ip 默认为空表示自动获取IP，多网卡时可手动设置指定IP，该IP不会绑定Host仅作为通讯实用；地址信息用于 \"执行器注册\" 和 \"调度中心请求并触发任务\"；</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.port 执行器Server端口号，默认端口为9999，单机部署多个执行器时，注意要配置不同执行器端口；</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.logpath 执行器运行日志文件存储磁盘路径,需要对该路径拥有读写权限;</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.logretentiondays 执行器日志文件保存天数,过期日志自动清理, 限制值大于等于3时生效; 否则, 如-1, 关闭自动清理功能；</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;executor.jsonpath datax json临时文件保存路径</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;pypath DataX启动脚本地址，例如：xxx/datax/bin/datax.py 如果系统配置DataX环境变量（DATAX_HOME），logpath、jsonpath、pypath可不配，log文件和临时json存放在环境变量路径下。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 4、运行项目</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 运行datax_admin下 DataXAdminApplication</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 运行datax_executor下 DataXExecutorApplication</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 5、打包</span></p><pre><code >修改pom文件，如果不修改，可能出现错误：主文件找不到\n&lt;plugin&gt;\n    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-boot-maven-plugin&lt;/artifactId&gt;\n    &lt;version&gt;2.2.1.RELEASE&lt;/version&gt;\n    &lt;executions&gt;\n        &lt;execution&gt;\n            &lt;goals&gt;\n                &lt;goal&gt;repackage&lt;/goal&gt;\n            &lt;/goals&gt;\n        &lt;/execution&gt;\n    &lt;/executions&gt;\n&lt;/plugin&gt;</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 6、bat运行</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; datax-main</span></p><pre><code >@echo off\n:: 设置Java路径和JAR文件路径\n:: set JAVA_HOME=\"D:\\JDK\\jdk-8u201\\bin\\java.exe\"\nset JAVA_HOME=\"java\"\n:: set JAR_FILE=\"E:\\code\\jar\\patient\\mrp-patient-start-2.0.0_rc3-SNAPSHOT.jar\"\nset JAR_FILE=\"E:\\datax-prod\\datax-admin\\datax-admin-2.1.2.jar\"\n:: 配置文件路径\nset CONFIG_FILE=\"E:\\datax-prod\\datax-admin\\application.yml\"\n:: 配置数据库\nset SQL_URL=\"--spring.datasource.url=jdbc:mysql://192.168.216.219:13306/datax_web?serverTimezone=Asia/Shanghai&useLegacyDatetimeCode=false&useSSL=false&nullNamePatternMatchesAll=true&useUnicode=true&characterEncoding=UTF-8\"\n:: 配置数据库密码\nset SQL_PASSWORD=\"--spring.datasource.password=password\"\n:: 配置日志\nset SYS_LOG=\"--logging.level.path=E:\\datax-prod\\datax-config\\applogs\\admin\"\n:: 设置Java启动参数 (如内存设置等)\nset JAVA_OPTS=-Xms512m -Xmx512m\n:: 检查JAR文件是否存在\nif not exist %JAR_FILE% (\n    echo JAR文件不存在: %JAR_FILE%\n    exit /b 1\n)\n:: 启动应用程序\necho 正在启动应用程序...\n%JAVA_HOME% %JAVA_OPTS% -jar %JAR_FILE% %SQL_URL% %SQL_PASSWORD% %SYS_LOG%\n:: 检查启动结果\nif %ERRORLEVEL% equ 0 (\n    echo 应用程序已成功启动！\n) else (\n    echo 应用程序启动失败！\n    exit /b 1\n)</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;datax-executor</span></p><pre><code >@echo off\n:: 设置Java路径和JAR文件路径\n:: set JAVA_HOME=\"D:\\JDK\\jdk-8u201\\bin\\java.exe\"\nset JAVA_HOME=\"java\"\n:: set JAR_FILE=\"E:\\code\\jar\\patient\\mrp-patient-start-2.0.0_rc3-SNAPSHOT.jar\"\nset JAR_FILE=\"E:\\datax-prod\\datax-executor\\datax-executor-2.1.2.jar\"\n:: 配置文件路径\nset CONFIG_FILE=\"E:\\datax-prod\\datax-executor\\application.yml\"\n:: 设置Java启动参数 (如内存设置等)\nset JAVA_OPTS=-Xms512m -Xmx512m\n:: Spring Boot的额外参数 (例如配置文件路径)\nset APP_OPTS=--spring.config.location=%CONFIG_FILE%\n:: 配置日志\nset SYS_PORT=\"--server.port=8081\"\n:: 配置日志\nset SYS_LOG=\"--logging.path=E:\\datax-prod\\datax-config\\applogs\\executor\\jobhandler\"\n:: 配置admin地址\nset DATAX_ADMIN=\"--datax.job.admin.addresses=http://127.0.0.1:8080\"\n:: 配置appname\nset DATAX_EXECUTOR_APPNAME=\"--datax.job.executor.appname=datax-executor\"\n:: 配置IP\nset DATAX_EXECUTOR_IP=\"--datax.job.executor.ip= \"\n:: 配置PORT\nset DATAX_EXECUTOR_PORT=\"--datax.job.executor.port=9999\"\n:: 配置Datax日志\nset DATAX_LOG=\"--datax.job.executor.logpath=E:\\datax-prod\\datax-config\\applogs\\executor\\jobhandler\"\n:: 配置Datax日志\nset DATAX_LOG=\"--datax.job.executor.logpath=E:\\datax-prod\\datax-config\\applogs\\executor\\jobhandler\"\n:: 配置logretentiondays\nset DATAX_EXECUTOR_LOGRETENTIONDAYS=\"--datax.job.executor.logretentiondays=30\"\n:: 配置jsonpath\nset DATAX_EXECUTOR_JSONPATH=\"--datax.executor.jsonpath=E:\\datax-prod\\datax-config\\temp\\executor\"\n:: 配置accessToken\nset DATAX_EXECUTOR_ACCESSTOKEN=\"--datax.job.accessToken= \"\n:: 配置Datax\nset DATAX_BIN=\"--datax.pypath=E:\\datax-prod\\datax-config\\datax\\bin\\datax.py\"\n:: 检查JAR文件是否存在\nif not exist %JAR_FILE% (\n    echo JAR文件不存在: %JAR_FILE%\n    exit /b 1\n)\n:: 启动应用程序\necho 正在启动应用程序...\n%JAVA_HOME% %JAVA_OPTS% -jar %JAR_FILE% %APP_OPTS% %SYS_PORT% %SYS_LOG% %DATAX_ADMIN% %DATAX_EXECUTOR_APPNAME% %DATAX_EXECUTOR_IP% %DATAX_EXECUTOR_PORT% %DATAX_LOG% %DATAX_EXECUTOR_LOGRETENTIONDAYS% %DATAX_EXECUTOR_ACCESSTOKEN% %DATAX_EXECUTOR_JSONPATH% %DATAX_BIN%\n:: 检查启动结果\nif %ERRORLEVEL% equ 0 (\n    echo 应用程序已成功启动！\n) else (\n    echo 应用程序启动失败！\n    exit /b 1\n)</code></pre><p><strong>错误解决</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 1、找不到或无法加载主类 com.alibaba.datax.core.Engine</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;py配置文件指向不对</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、在有总bps限速条件下，单个channel的bps值不能为空，也不能为非正数</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; ①、修改文件datax/conf/core.json</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 修改core -&gt; transport -&gt; channel -&gt; speed -&gt; \"byte\": -1</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/7fe4f818-4a9a-4878-a575-2295edb40276.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;②、json内容中删除总限速的配置</span></p><pre><code >\"setting\": {\n      \"speed\": {\n        \"channel\": 3\n }\n </code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、 启动datax-admin时，虽然启动成功了，但启动打印中出行了java.io.IOException: Could not locate executable null\\bin\\winutils.exe in the Hadoop binaries.提示。</span></p><p><span style=\"font-size: 16px;\"> 解决办法：这个是因为Windows中没有安装Hadoop，Hadoop并且目录bin文件下缺少 winutils.exe 文件导致的。解决办法安装Hadoop，注意我们安装到本地的Hadoop版本要和Datax-web项目中的版本一致</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4、Unable to open nested entry \'BOOT-INF/lib/HiveJDBC41.jar\'. It has been compressed</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/98fa8770-636f-4ab2-960c-8553d7b3f4b0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;需要将lib下的包jar中，但是不能直接解压软件放入，报错Caused by: java.lang.IllegalStateException: Unable to open nested entry \'BOOT-INF/lib/**.jar\'.It has been compressed and nested jar files must be stored without compression.Please check the mechanism used to create your executable jar file</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;解决方法</span></p><pre><code >先使用命令解压jar包：jar -xvf .\\test-protal.jar\n解压后会生成一个文件夹，然后将补丁直接放在文件夹里，再使用命令：jar -cfM0 test-portal.jar ./</code></pre><p><br></p><p><br></p><p><br></p>',0,1,0,0,1755095609,1756184460,NULL),(27,4,'Windows环境搭建Vue开发环境','Windows环境搭建Vue开发环境','Windows环境搭建Vue开发环境','/adminapi/uploads/image/20250813/9bb683d2-8930-4baa-919d-723eb3c94b5c.png','Amusing编程喵','<p><strong>一、安装node.js</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 官网：https://nodejs.org/en/download/</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 历史版本：https://nodejs.org/en/download/releases/</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/0ee653c6-aeee-4d90-98e4-f9829d7d0844.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;下载完毕后，可以安装node，建议不要安装在系统盘（如C：）。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/a235bb6b-689f-485e-87d4-9d0848385740.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>二、设置nodejs prefix（全局）和cache（缓存）路径</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、在nodejs安装路径下，新建node_global和node_cache &nbsp;两个文件夹</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/60c9e70a-94e8-4742-a6b4-14bdaf7b8ca9.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、设置缓存文件夹</span></p><pre><code >npm config set cache \"D:\\software\\NodeJs\\node_cache\"</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、设置全局模块存放路径</span></p><pre><code >npm config set prefix \"D:\\software\\NodeJs\\node_global\"</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;设置成功后，之后用命令npm install XXX -g安装以后模块就在D:\\vueProject\\nodejs\\node_global里</span></p><p><strong>三、基于 Node.js 安装cnpm（淘宝镜像）</strong></p><pre><code >npm install -g cnpm --registry=https://registry.npm.taobao.org</code></pre><p><strong>四、设置环境变量（非常重要）</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;说明：设置环境变量可以使得住任意目录下都可以使用cnpm、vue等命令，而不需要输入全路径</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、鼠标右键\"此电脑\"，选择“属性”菜单，在弹出的“系统”对话框中左侧选择“高级系统设置”，弹出“系统属性”对话框。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、修改系统变量PATH</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/7f20d5a8-3cdf-4b60-9023-a91472a89c9a.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、新增系统变量NODE_PATH</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/a9935e71-0e10-4d32-bb2c-c5d92aa2b70d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>五、安装Vue</strong></p><pre><code >cnpm install vue -g</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/36ac124d-4e2e-46f4-8fa0-a26dbcfd8b56.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>六、安装vue命令行工具，即vue-cli 脚手架</strong></p><pre><code >cnpm install vue-cli -g</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/ea17c01c-5acd-4b38-91f9-8c9f6171ca97.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>七、新项目的创建</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1.打开存放新建项目的文件夹</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 打开开始菜单，输入 CMD，或使用快捷键 win+R，输入 CMD，敲回车，弹出命令提示符。打开你将要新建的项目目录</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/38679275-a742-4c63-9d81-fe965f803a65.png\" alt=\"\" data-href=\"\" style=\"\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2.根据模版创建新项目</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 在当前目录下输入“vue init webpack-simple 项目名称（使用英文）”。</span></p><pre><code >vue init webpack-simple mytest</code></pre><p style=\"text-align: center;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;</span><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/ec8069ba-6767-44a7-b2d5-37d1abebd0ea.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;初始化完成后的项目目录结构如下：</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/aa4dd8f3-f02b-4508-bd77-a2c36bd9c4c1.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/308fce00-9eaf-4443-97c2-d6850fb72b76.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\">3、安装工程依赖模块</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 定位到mytest的工程目录下，安装该工程依赖的模块，这些模块将被安装在：mytest\\node_module目录下，node_module文件夹会被新建，而且根据package.json的配置下载该项目的modules</span></p><pre><code >cd mytest\ncnpm install</code></pre><p><span style=\"font-size: 16px;\"> 4、运行该项目，测试一下该项目是否能够正常工作，这种方式是用nodejs来启动。</span></p><pre><code >cnpm run dev</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/36d8b6de-035a-450e-b0d3-4cd619edc3dd.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/ae5e3681-0488-46e2-a506-9b276c24e156.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>八、借鉴网址：</strong></p><p><span style=\"font-size: 16px;\"><code> https://www.cnblogs.com/zhouyu2017/p/6485265.html </code></span></p><p><span style=\"font-size: 16px;\"><code>https://www.cnblogs.com/ixxonline/p/6007885.html </code></span></p><p><span style=\"font-size: 16px;\"><code>http://blog.csdn.net/zhuming3834/article/details/72778147 </code></span></p><p><span style=\"font-size: 16px;\"><code>https://www.cnblogs.com/fisheleven/p/6775380.html?utm_source=itdadao&amp;utm_medium=referral </code></span></p><p><br></p>',0,0,0,0,1755096712,1755096712,NULL),(28,4,'【环境搭建】Windows下安装Nacos','Windows下安装Nacos','Windows下安装Nacos','/adminapi/uploads/image/20250811/912fb0e3-53e4-4e2c-bc4a-c5fbab872c15.jpg','Amusing编程喵','<p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>一、下载Nacos</strong></span></p><pre><code >下载地址：https://github.com/alibaba/nacos/releases/tag/1.1.0\n所有下载地址：https://github.com/alibaba/nacos/releases</code></pre><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;选择这个zip下载。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/38fe87e3-55a0-4439-a42d-4978a23fcb90.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;下载完毕后我们可以看看目录结构：</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/46a255b2-cb2a-47c1-a3af-1968e5a684c7.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;这里的bin目录里面有windows启动文件startup.cmd，我们双击就能启动了，和大多数windows进程类似。启动后会有一个cmd窗口去打印命令并启动。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/38b22bee-133a-4684-896d-bfa23e3619ea.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;这里我们启动成功了，启动失败后窗口会一闪而过。</span></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>二、访问</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;访问地址：</span><a href=\"http://localhost:8848/nacos/index.html\" target=\"\"><span style=\"font-family: 宋体;\">http://localhost:8848/nacos/index.html</span></a></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/c2d3d862-eace-4e94-bbe7-742547e61f39.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"> <span style=\"font-family: 宋体;\"> &nbsp; 用户名密码：nacos/nacos</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/fe8ace36-8180-481b-b3b5-4c66516e0f31.png\" alt=\"\" data-href=\"\" style=\"width: 100%;\"></p><p style=\"line-height: 3;\"><span style=\"color: rgb(231, 95, 51); font-family: 宋体;\"><strong>三、配置数据库</strong></span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 可以自定义账号密码，并将账号密码存储进我们自己的数据库，需要修改/nacos/conf/application.properties文件，nacos默认使用的数据库为内嵌的cmdb</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp; 1、创建数据库nacos，并设置字符集utf8,如下</span></p><pre><code >CREATE DATABASE `nacos` CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;</code></pre><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;2、执行/nacos/conf/nacos-mysql.sql中的语句，创建表，并插入数据</span></p><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;3、修改/nacos/conf/application.properties文件，如下</span></p><pre><code >spring.datasource.platform=mysql\ndb.num=1\ndb.url.0=jdbc:mysql://127.0.0.1:3306/nacos?characterEncoding=utf8&connectTimeout=1000&socketTimeout=3000&autoReconnect=true&useUnicode=true&useSSL=false&serverTimezone=UTC\ndb.user=root\ndb.password=root</code></pre><p style=\"line-height: 3;\"><span style=\"font-family: 宋体;\"> &nbsp; &nbsp;验证登录，重启nacos，打开localhost:8848/nacos，输入默认账号密码，看是否可以正常登录</span></p><p><br></p>',0,2,1,0,1755097814,1756458443,NULL),(29,4,'Windows中OnlyOffice环境搭建','Windows中OnlyOffice环境搭建','Windows中OnlyOffice环境搭建','/adminapi/uploads/image/20250813/8720e3b3-9fd8-4466-b057-30ee40100ff7.png','Amusing编程喵','<h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">OnlyOffice安装步骤</span></h2><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;下载安装包，按照下面顺序依次安装：</span></p><ol><ol><li>otp_win64_19.1.exe</li><li>rabbitmq-server-3.5.4.exe</li><li>postgresql-9.6.0-1-windows-x64.exe</li></ol></ol><h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">一、创建数据库</span></h2><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 创建数据库有两种方式，一种是通过pgAdmin工具，另一种是通过命令行提示，第二种方式较为简单，下面分别介绍两种创建方式。</span></p><h3 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\"> 方法一</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 运行可执行文件。\"%ProgramFiles%\\PostgreSQL\\9.6\\pgAdmin 4\\bin\\pgAdmin4.exe\"</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 在 pgAdmin 窗口中，连接到 PostgreSQL server，并创建新的登录角色名称（onlyoffice）和密码（onlyoffice）。执行以下步骤：</span></p><ol><ol><li>右键单击左侧菜单中的 Login/Group Roles 项，然后选择 Create -&gt; Login/Group Role。</li><li>在打开的新窗口中输入名称字段（onlyoffice）。</li></ol></ol><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/99c4d06e-b235-4fcd-adbb-a19c761e39ae.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><ol><ol><li>切换到 Definition 选项卡并输入密码字段（onlyoffice）。</li><li>转到 Privileges 选项卡并单击 Can login? 切换器以设置 Yes 值。</li></ol></ol><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/5e8210d3-f7aa-4328-b256-e540b70f16e4.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><ol><ol><li>单击 Save 按钮。</li></ol></ol><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;创建数据库，选择创建的登录角色作为所有者。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;右键单击左侧菜单中的 Databases 项，选择 Create -&gt; Database… 在打开进入 Database 字段（onlyoffice）并选择一个角色（onlyoffice）在 Owner 列表在所有者列表中选择角色的新窗口中，然后单击\"保存\"。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/81d41b01-c01f-448c-8413-ddbf66e5b502.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h3 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">方法二</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 打开命令行窗口，执行以下命令：</span></p><pre><code >cd /D \"%ProgramFiles%\\PostgreSQL\\9.6\\bin\" psql -U postgres -c \"CREATE DATABASE onlyoffice;\" psql -U postgres -c \"CREATE USER onlyoffice WITH password \'onlyoffice\';\" psql -U postgres -c \"GRANT ALL privileges ON DATABASE onlyoffice TO onlyoffice;\"</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/41cd458b-39ab-4060-9887-3c3dfc3821ba.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong> 方法三</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 1、连接Postgres，创建角色，选择可以登录，设置密码</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/45ac4527-a55d-451a-bc4c-0b62aafa7d34.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 2、创建数据库，注意数据库名称和所有者</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/117c1b0b-5377-42d9-95c1-0ffe929a64ab.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">二、安装 OnlyOffice Docs</span></h2><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 一旦安装所有组件并创建数据库，就可以继续主程序安装。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 1、双击执行 onlyoffice-documentserver.exe 进行安装。</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 默认情况下，onlyoffice 会占用80 端口来进行监听传入的连接。如果你想改变这个端口，在执行安装的时候，需要传入参数，</span></p><pre><code >onlyoffice-documentserver.exe /DS_PORT=&lt;PORT_NUMBER&gt;\nonlyoffice-documentserver.exe /DS_PORT=你想要的端口号</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;将启动文档服务器设置向导。单击 Next &gt; 按钮以启动安装过程。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/70519da9-6640-4712-b204-9d8f4a1dbe3b.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;选择安装路径</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/7b16ba73-0fc5-4168-a9bc-a25fa90a0378.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;单击\"安装\"按钮，开始安装。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/4d34e1cc-2abf-45e4-a37d-0ae9ee41c82b.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;在配置后 Configuring PostgreSQL connection 对话窗口中，指定以下参数：</span></p><ul><ul><li>Host: localhost</li><li>User: onlyoffice</li><li>Password: onlyoffice</li><li>Database: onlyoffice</li></ul></ul><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/42de8332-c287-464b-b314-57fdc070bc67.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 在 Configuring RabbitMQ connection 窗口中，指定以下参数：</span></p><ul><ul><li>Host: localhost</li><li>User: guest</li><li>Password: guest</li></ul></ul><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/ba372c58-55c5-41c5-8262-636a50a5d098.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;安装过程完成后，单击\"完成\"按钮以关闭向导窗口。</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/6ba9e44e-fbf4-42bc-9f72-e8666fa54e45.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h2 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">三、浏览器访问</span></h2><pre><code >http://localhost/example</code></pre><p><strong>四、参考地址</strong></p><pre><code >https://helpcenter.onlyoffice.com/installation/docs-community-install-windows.aspx?_ga=2.205446096.1130940571.1667800322-236588065.1667800322</code></pre><p><strong>五、开发参考</strong></p><pre><code >https://api.onlyoffice.com/editors/basic</code></pre><p><br></p>',0,0,0,0,1755098809,1755098809,NULL),(30,4,'kkFileView部署（手动打包）','kkFileView部署（手动打包）','kkFileView部署（手动打包）','/adminapi/uploads/image/20250811/88a2ccb8-73a3-49be-b25c-20cefa6fecd1.png','Amusing编程喵','<h5 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">一、执行maven打包</span></h5><p style=\"text-align: left;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/e94ca198-87c1-497e-8670-f307442b3ced.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h5 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">二、上传部署包</span></h5><p><span style=\"font-size: 16px;\"> 利用Xftp上传kkFileView-4.4.0-SNAPSHOT.tar.gz部署包。</span></p><pre><code >[root@localhost kkFileView]# ls\nkkFileView-4.4.0-SNAPSHOT.tar.gz\n[root@localhost kkFileView]#</code></pre><h5 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">三、解压部署包</span></h5><p><span style=\"font-size: 16px;\"> 解压kkFileView-4.4.0-SNAPSHOT.tar.gz文件（Windows用.zip包，Linux/MacOS用.tar.gz包）</span></p><pre><code >[root@localhost kkFileView]# tar -zxvf kkFileView-4.4.0-SNAPSHOT.tar.gz\n<span style=\"font-size: 16px;\"> 打开解压后文件夹的bin目录，运行startup脚本（Windows下以管理员身份运行startup.bat，Linux以root用户运行startup.sh）。</span></code></pre><pre><code >[root@localhost bin]# pwd\n/opt/kkFileView/kkFileView-4.4.0-SNAPSHOT/bin\n[root@localhost bin]# ls\ninstall.sh  kkFileView-4.4.0-SNAPSHOT.jar  showlog.sh  shutdown.sh  startup.sh\n[root@localhost bin]# ./startup.sh</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/974c7ffe-6c50-4541-854e-c3fd8f7f0f2d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><strong>四、访问测试</strong></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/16dd0003-0c66-4462-9269-f2a9a325b599.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/a181df52-a1c6-4eee-8913-d4a720acf9a0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><strong>五、乱码解决</strong></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/bd697745-8656-413b-96e6-9a15a91877b9.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/d3be1e45-d871-4736-9f9a-780cda04f20e.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><span style=\"font-size: 16px;\">大部分Linux系统上并没有预装中文字体或字体不全，需要把常用字体拷贝到Linux服务器上，具体操作如下：下载如下字体包https://cowtransfer.com/s/4ca50f76643a4c 文件解压完整拷贝到Linux下的/usr/share/fonts目录。然后依次执行mkfontscale 、mkfontdir 、fc-cache使字体生效</span></p><pre><code >[root@localhost fonts]# unzip fonts.zip\n[root@localhost zhFonts]# cd zhFonts/\n[root@localhost zhFonts]# mkfontscale\n[root@localhost zhFonts]# mkfontdir\n[root@localhost zhFonts]# fc-cache</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/5787e786-bde3-4f80-a772-76cab97534a0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><strong>六、Windows使用</strong></p><p><span style=\"font-size: 16px;\">1、windows打包，自动生成zip，tar.gz</span></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/dc9b8ce5-3f0a-4442-ad60-61bf4392ff73.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><span style=\"font-size: 16px;\">2、复制到服务器，直接启动</span></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250813/61722529-92d4-4ea8-ae70-de53ff3b577d.png\" alt=\"\" data-href=\"\" style=\"\"/></p>',0,0,0,0,1755099389,1755099389,NULL),(31,4,'CentOS 安装mysql5.7','CentOS 安装mysql5.7','CentOS 安装mysql5.7','/adminapi/uploads/image/20250810/2b8c769e-c93c-4661-8472-fa7925854a5b.png','Amusing编程喵','<p><strong>一、数据库安装</strong></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/3e541d7f-89fa-4d47-96e2-e234d58ae4f8.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -qa | grep mysql</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/74cd131d-0737-4b3f-a085-a9ccbdf9e271.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -qa|grep -i mariadb</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/ae415276-df70-494a-ba23-9590901ed0c1.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -qa|grep mariadb|xargs rpm -e --nodeps</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/a000768c-acb4-4ea2-99fa-acd49f5634d4.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -qa|grep -i mariadb</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/bda940a8-6124-455c-810e-1c40bb4b8522.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >wget https://dev.mysql.com/get/mysql57-community-release-el7-9.noarch.rpm\n\nvim /etc/resolv.conf\nnameserver 8.8.8.8 #googleDNS\nnameserver 8.8.4.4 #googleDNS</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/42eca381-c4f7-4d8d-b432-e2da7a45b693.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -ivh mysql57-community-release-el7-9.noarch.rpm</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/d192f06a-7a9b-455a-a76a-054a6cce13b8.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >yum install mysql-server</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/09c942d3-87f1-44a7-90fe-0ee27958a1fa.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >yum install mysql-server --nogpgcheck</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/d328b088-3bdc-4360-9ec5-654430c27c37.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >rpm -qa | grep mysql</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/4af4376d-afef-400e-9fd0-c29a319e2ead.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >systemctl start mysqld.service #启动 mysql\nsystemctl restart mysqld.service #重启 mysql\nsystemctl stop mysqld.service #停止 mysql\nsystemctl enable mysqld.service #设置 mysql 开机启动</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/959bb407-1550-46f7-b8a0-c3844b588cd0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >cat var/log/mysqld.log</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/f465516c-4646-45e3-a42f-3e62894245c1.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/1d99627a-4350-4e7b-b761-c884d4827249.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >mysql -uroot -p # 输入上步查到的密码。\nalter user \'root\'@\'localhost\' identified BY \'Mysql@135269\';\n# 如果密码太简单，会提示。需要修改下面2个参数。\nSHOW VARIABLES LIKE \'validate_password%\';\nset global validate_password_policy=LOW;\nset global validate_password_length=6;\n\nquit 退出</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/b4da1da0-7b7a-4257-b198-16a9f467760e.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >GRANT ALL PRIVILEGES ON *.* TO root@\"%\" IDENTIFIED BY \"root\";\n\nflush privileges;</code></pre><p> &nbsp; &nbsp;如果GRANT ALL PRIVILEGES ON *.* TO root@\"%\" IDENTIFIED BY \"root\";授权之后，远程连接还是失败，使用下面授权</p><pre><code >grant all privileges on *.* to root@\'%\' identified by \'Mysql@135269\';</code></pre><p> &nbsp; &nbsp;错误：Your password does not satisfy the current policy requirements，如果试了很多方法都不可以，那就删除密码验证插件：</p><pre><code >mysql&gt; uninstall plugin validate_password;</code></pre><p> &nbsp; &nbsp;卸载方法一(适用于rpm安装方式安装的MySQL)</p><p> &nbsp; &nbsp; 执行命令rpm -e –nodeps 包名删除MySQL包(查到的全部包都删掉，只删一个不行)</p><pre><code >rpm -e –nodeps community-server-8.0.32-1.el7.x86_64(包名换成你自己查询到的)</code></pre><p> &nbsp; &nbsp;卸载方法二(适用于yum安装方式安装的MySQL)</p><p> &nbsp; &nbsp; 依次执行下方命令即可卸载MySQL(包名换成你自己查询到的)</p><pre><code >yum remove community-server-8.0.32-1.el7.x86_64\n#卸载mysql依赖\nyum remove mysql-libs\nyum remove mysql-server\nyum remove perl-DBD-MySQL\nyum remove mysql</code></pre><p><strong>二、创建用户</strong></p><pre><code >CREATE USER \'username\'@\'%\' IDENTIFIED BY \'password\';\nusername：你将创建的用户名；\n%：指定该用户在哪个主机上可以登录，%表示该用户可以从任意远程主机登录，如果是本地用户可用localhost；\npassword：该用户的登录密码，密码可以为空，如果为空则该用户可以不需要密码登录服务器。\n\n查看所有的用户\nselect user,host from mysql.user;</code></pre><p style=\"text-align: center;\"> &nbsp; &nbsp;<img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/d09b0350-9a8c-4e05-8b3a-40b3b6e77cc7.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;1.host字段中，localhost表示只允许本机访问，要实现远程连接，可以将root用户的host改为%，%表示允许任意host访问；如果需要设置只允许特定ip访问，则应改为对应的ip。</p><p> &nbsp; &nbsp;2.修改root用户的host字段，命令：update user set host=\"%\" where user=\"root\"</p><p> &nbsp; &nbsp;3.使本次修改立即生效，命令：flush privileges</p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/ee1e7850-6922-4098-be3f-3100b56fba11.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >SELECT * FROM mysql.user WHERE user=\'root\'</code></pre><p> &nbsp; <img src=\"https://zy.wlown.com/adminapi/uploads/image/20250815/01d75d1c-805a-4a97-9c78-05ee4dea9291.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p> &nbsp; &nbsp; Select_priv：确定用户是否可以通过SELECT命令选择数据</p><p> &nbsp; &nbsp; Insert_priv：确定用户是否可以通过INSERT命令插入数据</p><p> &nbsp; &nbsp; Update_priv：确定用户是否可以通过UPDATE命令修改现有数据</p><p> &nbsp; &nbsp; Delete_priv：确定用户是否可以通过DELETE命令删除现有数据</p><p> &nbsp; &nbsp; Create_priv：确定用户是否可以创建新的数据库和表</p><p> &nbsp; &nbsp; Drop_priv：确定用户是否可以删除现有数据库和表</p><p> &nbsp; &nbsp; Reload_priv：确定用户是否可以执行刷新和重新加载MySQL所用各种内部缓存的特定命令，包括日志、权限、主机、查询和表</p><p> &nbsp; &nbsp; Shutdown_priv：确定用户是否可以关闭MySQL服务器，将此权限提供给root账户之外的任何用户时，都应当非常谨慎</p><p> &nbsp; &nbsp; Process_priv：确定用户是否可以通过SHOW</p><p> &nbsp; &nbsp; File_priv：确定用户是否可以执行SELECT INTO OUTFILE和LOAD DATA INFILE命令</p><p> &nbsp; &nbsp; Grant_priv：确定用户是否可以将已经授予给该用户自己的权限再授予其他用户，例如，如果用户可以插入、选择和删除foo数据库中的信息，并且授予了GRANT权限，则该用户就可以将其任何或全部权限授予系统中的任何其他用户</p><p> &nbsp; &nbsp; References_priv：目前只是某些未来功能的占位符，现在没有作用</p><p> &nbsp; &nbsp; Index_priv：确定用户是否可以创建和删除表索引</p><p> &nbsp; &nbsp; Alter_priv：确定用户是否可以重命名和修改表结构</p><p> &nbsp; &nbsp; Show_db_priv：确定用户是否可以查看服务器上所有数据库的名字，包括用户拥有足够访问权限的数据库，可以考虑对所有用户禁用这个权限，除非有特别不可抗拒的原因</p><p> &nbsp; &nbsp; Super_priv：确定用户是否可以执行某些强大的管理功能，例如通过KILL命令删除用户进程，使用SET GLOBAL修改全局MySQL变量，执行关于复制和日志的各种命令</p><p> &nbsp; &nbsp; Create_tmp_table_priv：确定用户是否可以创建临时表</p><p> &nbsp; &nbsp; Lock_tables_priv：确定用户是否可以使用LOCK</p><p> &nbsp; &nbsp; Execute_priv：确定用户是否可以执行存储过程，此权限只在MySQL 5.0及更高版本中有意义</p><p> &nbsp; &nbsp; Repl_slave_priv：确定用户是否可以读取用于维护复制数据库环境的二进制日志文件，此用户位于主系统中，有利于主机和客户机之间的通信</p><p> &nbsp; &nbsp; Repl_client_priv：确定用户是否可以确定复制从服务器和主服务器的位置</p><p> &nbsp; &nbsp; Create_view_priv：确定用户是否可以创建视图，此权限只在MySQL 5.0及更高版本中有意义</p><p> &nbsp; &nbsp; Show_view_priv：确定用户是否可以查看视图或了解视图如何执行，此权限只在MySQL 5.0及更高版本中有意义 Create_routine_priv：确定用户是否可以更改或放弃存储过程和函数，此权限是在MySQL 5.0中引入的 &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Alter_routine_priv：确定用户是否可以修改或删除存储函数及函数，此权限是在MySQL 5.0中引入的 Create_user_priv：确定用户是否可以执行CREATE</p><p> &nbsp; &nbsp; Event_priv：确定用户能否创建、修改和删除事件，这个权限是MySQL 5.1.6新增的</p><p> &nbsp; &nbsp; Trigger_priv：确定用户能否创建和删除触发器，这个权限是MySQL 5.1.6新增的</p><p> &nbsp; &nbsp; Create_tablespace_priv: 创建表的空间</p><p><strong>四、授予用户权限</strong></p><pre><code >GRANT privileges ON databasename.tablename TO \'username\'@\'localhost\';\nFLUSH PRIVILEGES;</code></pre><p> &nbsp; &nbsp;privileges：用户的操作权限，如SELECT，INSERT，UPDATE等，如果要授予所有的权限则使用ALL；</p><p> &nbsp; &nbsp;databasename：数据库名,如果要授予该用户对所有数据库的操作权限则可用 * 表示；</p><p> &nbsp; &nbsp;tablename：表名，如果要授予该用户对所有数据库和表的相应操作权限则可用 * 表示。</p><p> &nbsp; &nbsp;授予某个用户对全部数据库的所有操作</p><pre><code >GRANT ALL ON *.* TO \'root\'@\'%\';\nFLUSH PRIVILEGES;</code></pre><p> &nbsp; &nbsp;授予某个用户对某个数据库的全部表的所有操作</p><pre><code >GRANT ALL ON student.* TO \'root\'@\'%\';\nFLUSH PRIVILEGES;</code></pre><p> &nbsp; &nbsp;查看该用户的权限：</p><pre><code >show grants for root;</code></pre><h2 style=\"line-height: 1.5;\">五、撤销用户权限</h2><pre><code >REVOKE privilege ON databasename.tablename FROM \'username\'@\'%\';\nFLUSH PRIVILEGES;</code></pre><h2 style=\"line-height: 1.5;\">六、删除用户</h2><pre><code >DROP USER \'username\'@\'%\';\nFLUSH PRIVILEGES;</code></pre><h2 style=\"line-height: 1.5;\">七、更改用户密码</h2><pre><code >SET PASSWORD FOR \'username\'@\'localhost\' = PASSWORD(\'newpassword\');\nFLUSH PRIVILEGES;</code></pre><h2 style=\"line-height: 1.5;\">八、注意</h2><pre><code >创建和设置一个MySQL用户最后的一个重要步骤：\nFLUSH PRIVILEGES;</code></pre><p><br></p>',0,0,0,0,1755214897,1755351651,NULL),(32,4,'CentOS安装ElasticSearch','CentOS安装ElasticSearch','CentOS安装ElasticSearch','/adminapi/uploads/image/20250816/623a15d4-cc12-4c66-88d5-a6d63abd0f24.png','Amusing编程喵','<p><strong>1、下载Elasticsearch</strong></p><pre><code >https://www.elastic.co/cn/downloads/past-releases#elasticsearch</code></pre><h3><span style=\"font-size: 16px;\">2、Linux单机版的安装</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;可以采用安装tar.gz的方式，也可以采用rpm的方式进行，推荐使用rpm方式，注册到系统服务中，方便启动和停止。</span></p><h4><span style=\"font-size: 16px;\">2.1 安装tar.gz包</span></h4><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;软件下载地址</span></p><ul><li>快 https://repo.huaweicloud.com/elasticsearch/</li><li>慢 https://www.elastic.co/cn/downloads/past-releases#elasticsearch</li></ul><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;解压软件</span></p><pre><code >tar -zxvf elasticsearch-7.4.2-linux-x86_64.tar.gz -C /usr/local/</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改配置文件</span></p><pre><code >/usr/local/elasticsearch-7.4.2/config\nvi elasticsearch.yml\n# 加入如下配置\n# 修改当前节点名称\ncluster.name: elasticsearch\n# 修改集群名称\nnode.name: node-1\n# 修改data数据保存地址\npath.data=/usr/local/elasticsearch-7.4.2/data\n# 修改log数据保存地址\npath.log=usr/local/elasticsearch-7.4.2/log\n# 修改ip允许访问地址\nnetwork.host: 0.0.0.0\n# 修改访问端口\nhttp.port: 9200\n# 集群初始化节点\ncluster.initial_master_nodes: [\"node-1\"]</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改JVM参数</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/eb4d481e-c186-4adf-9850-778e11686a96.png\" alt=\"\" data-href=\"\" style=\"\"></p><pre><code >-Xms128m -Xmx256m</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;创建用户</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;因为安全问题，Elasticsearch 不允许 root 用户直接运行，所以要创建新用户。</span></p><pre><code ># 添加esuser用户 useradd esuser \n# 赋权 chown -R esuser:esuser /usr/local/elasticsearch-7.4.2/\n\n修改 /etc/security/limits.conf\n# 每个进程可以打开的文件数的限制\n* soft nofile 65536\n* hard nofile 131072\n# 操作系统级别对每个用户创建的进程数的限制\n* soft nproc 2048\n* hard nproc 4096\n\n修改/etc/sysctl.conf\n# 在文件中增加下面内容\n# 一个进程可以拥有的 VMA(虚拟内存区域)的数量,默认值为 65536\nvm.max_map_count=655360</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;重新加载</span></p><pre><code >sysctl -p</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;启动软件</span></p><pre><code >su esuser\n# 进入$ES_HOME/bin\ncd /usr/local/elasticsearch-7.4.2/bin\n# 后台启动es\n./elasticsearch -d</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;停止服务</span></p><pre><code ># 查找es服务\nps -ef |grep elastic\n# 杀掉es进程\nkill -9 xxx(进程号)</code></pre><h4><span style=\"font-size: 16px;\">2.2 安装rpm包</span></h4><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;下载地址同上，选择rpm包</span></p><pre><code >rpm -ivh elasticsearch-7.6.2.rpm\n\n修改配置文件\n# 加入如下配置\n# 修改当前节点名称\ncluster.name: elasticsearch\n# 修改集群名称\nnode.name: node-1\n# 修改data数据保存地址\npath.data=/usr/local/elasticsearch-7.4.2/data\n# 修改log数据保存地址\npath.log=usr/local/elasticsearch-7.4.2/log\n# 修改ip允许访问地址\nnetwork.host: 0.0.0.0\n# 修改访问端口\nhttp.port: 9200\n# 集群初始化节点\ncluster.initial_master_nodes: [\"node-1\"]</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;修改文件所有者</span></p><pre><code >chown elasticsearch:elasticsearch -R /usr/local/elasticsearch-7.4.2/</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;启动elasticsearch</span></p><pre><code >systemctl start elasticsearch</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;查看es启动状态</span></p><pre><code >systemctl status elasticsearch</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;如果从系统服务不太容易观察到启动失败错误信息，也可以先通过安装路径启动es</span></p><pre><code >/usr/share/elasticsearch/bin/elasticsearch</code></pre><h3><span style=\"font-size: 16px;\">2.3 Linux集群版搭建</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 与单机版基本相同，只是配置文件略有不同</span></p><pre><code >#集群名称\ncluster.name: cluster-es #节点名称，每个节点的名称不能重复 node.name: node-1\n#ip 地址，每个节点的地址不能重复\nnetwork.host: node107 #是不是有资格主节点 node.master: true node.data: true http.port: 9200\n# head 插件需要这打开这两个配置\nhttp.cors.allow-origin: \"*\"\nhttp.cors.enabled: true\nhttp.max_content_length: 200mb\n#es7.x 之后新增的配置，初始化一个新的集群时需要此配置来选举 master cluster.initial_master_nodes: [\"node-1\"]\n#es7.x 之后新增的配置，节点发现\ndiscovery.seed_hosts: [\"node107:9300\",\"node108:9300\",\"node109:9300\"]\ngateway.recover_after_nodes: 2\nnetwork.tcp.keep_alive: true\nnetwork.tcp.no_delay: true\ntransport.tcp.compress: true\n#集群内同时启动的数据任务个数，默认是 2 个 cluster.routing.allocation.cluster_concurrent_rebalance: 16 #添加或删除节点及负载均衡时并发恢复的线程个数，默认 4 个 cluster.routing.allocation.node_concurrent_recoveries: 16 #初始化数据恢复时，并发恢复线程的个数，默认 4 个 cluster.routing.allocation.node_initial_primaries_recoveries: 16\n</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/547e78e6-63a1-460c-9e46-ae7100b1ee0c.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"><span style=\"font-size: 16px;\"> &nbsp; </span></p><p><span style=\"font-size: 16px;\"> 问题解决：</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、initial heap size [134217728] not equal to maximum heap size [268435456]; this can cause resize pauses and prevents mlockall from locking the entire heap </span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/6d57d2bb-eae6-489e-8f01-aa8099399d55.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、max virtual memory areas vm.max_map_count [65530] is too low, increase to at least [262144]</span></p><pre><code >切换到 root,执行命令\nsysctl -w vm.max_map_count=262144\n查看结果：\nsysctl -a|grep vm.max_map_count\n上述重启后就失效，永久生效的办法：\n在   /etc/sysctl.conf文件最后添加一行\nvm.max_map_count=262144</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;3、the default discovery settings are unsuitable for production use; at least one of [discovery.seed_hosts, discovery.seed_providers, cluster.initial_master_nodes] must be configured</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/a62cb797-1a30-41a5-9e43-995f622c04fe.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p>',0,0,0,0,1755351116,1755351116,NULL),(33,4,'CentOS安装Kibana','CentOS安装Kibana','CentOS安装Kibana','/adminapi/uploads/image/20250816/8891d9cc-195c-411d-ad15-cc65d7f56005.jpeg','Amusing编程喵','<p><strong>1、下载</strong></p><pre><code >wget https://artifacts.elastic.co/downloads/kibana/kibana-7.0.0-linux-x86_64.tar.gz</code></pre><p><strong>2、解压</strong></p><pre><code >tar -zxvf kibana-7.6.2-linux-x86_64.tar.gz -C /usr/local/</code></pre><p><strong>3、配置文件</strong></p><pre><code >cd /usr/local/kibana/\n\n#端口号\nserver.port: 5601\n#kibana的主机地址\nserver.host: \"0.0.0.0\"\n#elasticsearch的ip和端口\nelasticsearch.hosts: [\"http://192.168.1.1:9200\"]\n\n#下面两项，需要开启RBAC时需要打开配合es使用\n#elasticsearch.username: \"user\"\n#elasticsearch.password: \"pass\"\n\n或者：\nvi config/kibana.yml\n\nserver.port: 5601\nserver.host: \"192.168.2.109\"\nelasticsearch.hosts: [\"http://192.168.2.109:9200\"]\nlogging.dest: /var/log/kibana/kibana.log\ni18n.locale: \"zh-CN\"\n\n# 创建 日志目录\nmkdir /var/log/kibana</code></pre><p><strong>4、因Kibana不能以root用户启动,把Kibana移到es的用户目录下面(我自己的es用户是es_user1,用户组是es_users),然后给权限</strong></p><pre><code >chown -R esuser:esuser /usr/local/kibana-7.6.2-linux-x86_64</code></pre><p><strong>5、启动</strong></p><pre><code >#切换到es_user1用户下\nsu es_user1\n#启动\n.bin/kibana\n\nnohup ./kibana &gt; /dev/null 2&gt;&1 &</code></pre><p><strong>6、验证是否启动成功</strong></p><pre><code >lsof -i:5601</code></pre><p><br></p>',0,0,0,0,1755351361,1755351653,NULL),(34,4,'CentOS安装Logstash','CentOS安装Logstash','CentOS安装Logstash','/adminapi/uploads/image/20250816/31903979-36d7-4830-96f5-3a202561e28c.png','Amusing编程喵','<p><strong>1、下载</strong></p><pre><code >https://artifacts.elastic.co/downloads/logstash/logstash-7.6.0.tar.gz</code></pre><p><strong>２、解压</strong></p><pre><code >tar -zxvf logstash-7.6.2.tar.gz -C /usr/local/\ncd /usr/local/logstash</code></pre><p><strong>３、配置文件</strong></p><pre><code >复制logstash-sample.conf，或者新建\nvi config/logstash.conf\n\n# 修改内容\ninput {\n    # 系统日志\n    file {\n        path =&gt; [ \"/var/log/messages\" ]\n        type =&gt; \"system\"\n        start_position =&gt; \"beginning\"\n    }\n    # nginx 日志\n    file {\n        path =&gt; [ \"/var/log/nginx/access.log\" ]\n        type =&gt; \"nginx\"\n        start_position =&gt; \"beginning\"\n    }\n}\noutput {\n    if [type] == \"system\" {\n        elasticsearch {\n            hosts =&gt; [\"192.168.2.106:9200\"]\n            index =&gt; \"system-%{+YYYY.MM.dd}\"\n        }\n    }\n    if [type] == \"nginx\" {\n        elasticsearch {\n            hosts =&gt; [\"192.168.2.106:9200\"]\n            index =&gt; \"nginx-%{+YYYY.MM.dd}\"\n        }\n    }\n}</code></pre><p><span style=\"font-size: 16px;\">４、启动</span></p><pre><code >cd logstash-7.6.2/bin \n./logstash -f ../config/logstash.conf\n\nnohup ./logstash &</code></pre><p><br></p>',0,1,0,0,1755351648,1756184464,NULL),(35,4,'CentOS中Java rpm安装与配置','CentOS中Java rpm安装与配置','CentOS中Java rpm安装与配置','/adminapi/uploads/image/20250811/13010917-e9ea-4a6a-92a6-ad19d9af8cae.jpeg','Amusing编程喵','<p><strong>1、查看当前Linux系统是否已经安装java</strong></p><pre><code >rpm -qa | grep java</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;rpm是管理套件命令，-qa表示使用询问模式查询所有套件；grep表示查询文件里符合条件的字符串；java表示查询包含java的字符串</span></p><p><strong>2、如果有则卸载两个openJDK，没有则跳过此步骤至第三步</strong></p><pre><code >rpm -e --nodeps java-1.7.0-openjdk-1.7.0.221-2.6.18.0.el7_6.x86_64\nrpm -e --nodeps java-1.7.0-openjdk-headless-1.7.0.221-2.6.18.0.el7_6.x86_64\nrpm -e --nodeps java-1.8.0-openjdk-1.8.0.212.b04-0.el7_6.x86_64\nrpm -e --nodeps java-1.8.0-openjdk-headless-1.8.0.212.b04-0.el7_6.x86_64</code></pre><p><strong>3、下载JDK</strong></p><pre><code >wget https://repo.huaweicloud.com/java/jdk/8u201-b09/jdk-8u201-linux-x64.tar.gz\n或官网下载上传</code></pre><p><strong>4、解压JDK</strong></p><pre><code >tar -zxvf jdk-8u201-linux-x64.tar.gz</code></pre><p><strong>5、配置环境变量</strong></p><pre><code >vim /etc/profile\n\n#java enviroment\nexport JAVA_HOME=/root/jdk1.8.0_201\nexport CLASSPATH=.:${JAVA_HOME}/jre/lib/rt.jar:${JAVA_HOME}/lib/dt.jar:${JAVA_HOME}/lib/tools.jar\nexport PATH=$PATH:${JAVA_HOME}/bin</code></pre><p><strong>6、设置环境生效</strong></p><pre><code >source /etc/profile</code></pre><p><strong>7、验证</strong></p><pre><code >Java -version\nJava\nJavac</code></pre><p><br></p>',0,1,0,0,1755351827,1756217976,NULL),(36,4,'Docker安装Mysql','Docker安装Mysql','Docker安装Mysql','/adminapi/uploads/image/20250810/2b8c769e-c93c-4661-8472-fa7925854a5b.png','Amusing编程喵','<h2 style=\"line-height: 2;\"><span style=\"font-size: 16px;\">1、在docker hub 上查看要下载的mysql镜像名称</span></h2><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;dockerHub官网地址，在上方搜索栏里输入mysql</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/440bde62-9aff-46fe-8faf-54acc367ce02.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;找到要拉取的镜像版本，在tag下找到版本</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/566d26ec-0b32-4390-86cd-1d1320cc4c21.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;回到虚拟机界面，执行下面命令来拉取mysql镜像，不指定版本号，默认下载最新版本:</span></p><pre><code >sudo docker pull mysql</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;指定版本号:</span></p><pre><code >sudo docker pull mysql:5.7</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/bb33fa05-d706-4f47-931f-37c74212c11b.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h2 style=\"line-height: 2;\"><span style=\"font-size: 16px;\">2、镜像拉取完成后，用该镜像创建mysql实例,使用下面的命令来创建</span></h2><pre><code >sudo docker run \\\n-p 3306:3306 --name mysql \\\n-v /mydata/mysql/log:/var/log/mysql \\\n-v /mydata/mysql/data:/var/lib/mysql \\\n-v /mydata/mysql/conf:/etc/mysql \\\n-e MYSQL_ROOT_PASSWORD=root \\\n-d mysql:5.7</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;这里对上面的参数做下简单的介绍，如果不想了解这一块直接复制上面的命令执行即可:</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 配置端口映射：</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; &nbsp;-p 3306:3306 --name mysql将容器的3306端口映射到主机的3306端口</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 配置mysql数据卷挂载：</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; &nbsp;-v &lt;宿主机目录绝对路径:容器内目录绝对路径&gt;</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 1.-v /mydata/mysql/log:/var/log/mysql(日志文件挂载)</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 将容器中的日志文件夹挂载到主机对应的/mydata/mysql/log文件夹中</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 2.-v /mydata/mysql/data:/var/lib/mysql(数据文件挂载)</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 将容器中的数据文件夹挂载到主机对应的/mydata/mysql/data文件夹中</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 3.-v /mydata/mysql/conf:/etc/mysql(配置文件挂载)</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 将容器的配置文件夹挂载到主机对应的/mydata/mysql/conf文件夹中，注(这里所提的主机指的是当前的linux主机)</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 4.-e MYSQL_ROOT_PASSWORD=root</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 配置用户，设置初始化root用户的密码</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 5.-d mysql:5.7</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 指定镜像资源，-d：以后台方式运行实例，mysql:5.7：指定用这个镜像来创建运行实例</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 下面演示是用root用户来执行的命令，如果当前不是root用户，要在命令前加 sudo，以管理员方式来运行</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/51aa70b0-cd18-471c-b442-cf976b0e0b7c.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;创建成功后使用下面命令查看下创建好的mysql实例: </span></p><pre><code >docker ps -a</code></pre><p style=\"text-align: center;\"><span style=\"font-size: 16px;\"> &nbsp; &nbsp;</span><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/59cda34c-6f3f-41fd-b46c-9129ef8c6edf.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;用navicat测试下数据库是否启动成功：</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;用户名密码刚才创建docker时均设为了root，点击测试连接，显示测试成功，说明docker的mysql实例已经正常启动</span></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/d770f4e7-1a88-449a-8ead-e3f1ed7f6fa7.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h3 style=\"line-height: 2;\"><span style=\"font-size: 16px;\">2.1、进入容器</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; # 进入容器 bash/sh 都可以</span></p><pre><code >docker exec -it 容器ID /bin/bash</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;例如mysql的容器ID：</span></p><pre><code >docker ps</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/e2ad1e4a-3cdc-4b49-8c5a-9c2040313834.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><pre><code >docker exec -it 981fe6284798 /bin/bash</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/2b47862d-1cf2-4b76-b2b6-3dd01cbca578.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h3 style=\"line-height: 2;\"><span style=\"font-size: 16px;\">2.2、配置my.cnf</span></h3><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;在宿主机映射地址中配置my.cnf</span></p><pre><code >cd /mydata/mysql/conf\nvim my.cnf\nmy.cnf 基本默认内容\n[mysqld]\ndatadir=/var/lib/mysql\nsocket=/var/lib/mysql/mysql.sock\n# Disabling symbolic-links is recommended to prevent assorted security risks\nsymbolic-links=0</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;重启容器</span></p><pre><code >docker stop 容器ID\ndocker start 容器ID</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;</span><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/aff88221-d63a-4d79-86a7-c065caf9bbc6.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;当指定了外部配置文件与外部存储路径时，也需要指定 /var/lib/mysql-files的外部目录，所以在 主机新建/home/mysql/mysql-files目录，在启动容器时需要加上</span></p><pre><code >-v /home/mysql/mysql-files:/var/lib/mysql-files/\ndocker run -d -p 3305:3306 -e MYSQL_ROOT_PASSWORD=123456 --name mysqltest5 -v /home/mysql/data:/ var /lib/mysql -v /home/mysql/conf/my.cnf:/etc/mysql/my.cnf -v /home/mysql/mysql-files:/ var /lib/mysql-files/    mysql</code></pre><p><br></p>',0,0,0,0,1755352620,1756184492,NULL),(37,4,'Docker可视化工具portainer','Docker可视化工具portainer','Docker可视化工具portainer','/adminapi/uploads/image/20250816/ba2e0307-1896-4694-af0c-6d3651485a42.png','Amusing编程喵','<p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/1e2e61f5-7a9c-4a10-b712-26873a1e448a.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><pre><code >docker search portainer</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/6eb4e48a-ea9b-4e71-8c60-014e24697321.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h2>2. 拉取portainer镜像</h2><pre><code >docker pull lihaixin/portainer</code></pre><h2>3. 启动portainer容器</h2><pre><code ># 启动镜像\ndocker run -d -p 10015:9000 --restart=always \\\n-v /var/run/docker.sock:/var/run/docker.sock \\\n--name portainer lihaixin/portainer</code></pre><h2>4. docker ps查看容器</h2><pre><code >docker ps\n# 查看日志\ndocker logs -f portainer</code></pre><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/55ba7338-5c52-4dcf-b99a-a542cec50390.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/20713711-1a81-4e7f-8173-efe7ff9db9b8.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/67f396c8-1639-440e-8813-20f557982161.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/30f4c6ef-39c7-408f-9b09-ed9136eaee13.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/b7113122-4e6d-4ae0-a097-b80cfdce3edf.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/ac320b82-4d46-4416-b525-72a3acb76767.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/ae54e20b-4142-470d-9cfb-09cdef030196.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p>',0,0,0,0,1755353307,1756184487,NULL),(38,4,'Windows中Git下载、安装与环境配置','Windows中Git下载、安装与环境配置','Windows中Git下载、安装与环境配置','/adminapi/uploads/image/20250816/1da0b127-aaaa-444c-a611-c4b9d9cf9fc0.png','Amusing编程喵','<p><strong>一、Git下载</strong></p><pre><code >https://git-scm.com/downloads/win</code></pre><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/5fcc1cf5-5281-4f54-ba97-43339ac4949f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>二、安装过程</strong></p><p> &nbsp; &nbsp;1. 下载完成后，双击下载好的软件开始安装，出现如下对话框</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/5fbb7bb0-9221-4982-b616-10696da313f0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;2. 点击Next，默认选项和图中不一样，建议按照图中修改，Git Bash Here和Git GUI Here可以方便的在任意目录下打开git，建议选中，选中这两项后Additional icons-&gt;On the Desktop就按照自己心情了。</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/46862acc-5316-4168-9146-214e36d2bb61.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;这一步根据自己需要设置后，不爱折腾的小伙伴下面的步骤可以直接采用默认选项，当然也可以详细研究选择最适合自己的。</p><p> &nbsp; &nbsp;3. 点击next,选择默认编辑器，我选择的是Notepad++。</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/ea763119-efd7-4f1d-854e-d672cefe35a0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;4. 继续next,配置PATH环境。</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/084486e6-63c0-4630-b56b-e0149c8d8891.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;Use Git from Git Bash only：这是最安全的选择，因为你的PATH根本不会被修改，你只能使用Git Bash的Git命令行工具。</p><p> Use Git from the Windows Command Prompt：这个选项被认为是安全的，它只向PATH添加一些最小的Git包，以避免使用可选的Unix工具混淆环境。你将能够从Git Bash和Windows命令提示符中使用Git。建议选择此项。</p><p> Use Git and optional Unix tools from the Windows Command Prompt：Git和可选的Unix工具都将添加到计算机的PATH中。警告：这将覆盖Windows工具，如“find”和“sort”，只有在了解其含义后才使用此选项。</p><p> &nbsp; &nbsp;5. 继续next，以下选项均为默认。</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/c5f3cc0e-8f51-4dc5-82a5-9a1155073467.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/de5457b1-c869-4f89-99f5-fa1d047edb4f.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/97d5436c-5b8e-4a19-b59e-04ec966730e3.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/0c09fbe5-d959-4ec2-b998-61bdd910f8fb.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p> &nbsp; &nbsp;点击Inall开始安装，安装完成后点击Finish即可。在开始菜单里点击“Git“Git Bash”，弹出类似命令行的窗口，就说明Git安装成功！在任意目录下右击，可以看到右键菜单中有Git GUI Here和Git Bash Here两个选项。</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/e9b4259a-2e49-4df7-99c5-29336a8c27f0.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: left;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/2856824e-01e7-494f-ab93-52be892e9ccd.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p style=\"text-align: left;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/b4d4f3fa-940a-48e1-9d67-55f2f8204ed3.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p><strong>三、环境配置</strong></p><p> &nbsp; &nbsp; 1、git安装好去GitHub上注册一个账号，注册好后，点击桌面上的Git Bash快捷图标，我们要用账号进行环境配置</p><p>  &nbsp; &nbsp;2、配置git</p><pre><code ># 配置用户名\ngit config --global user.name \"username\"    //（ \"username\"是自己的账户名，）\n# 配置邮箱\ngit config --global user.email \"username@email.com\"     //(\"username@email.com\"注册账号时用的邮箱)</code></pre><p> &nbsp; &nbsp;3、生成ssh</p><pre><code >ssh-keygen -t rsa</code></pre><p> &nbsp; <img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/1707d7fe-0ed9-4b89-8881-071a799a50a8.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p> &nbsp; &nbsp; 4、 将ssh文件夹中的公钥（ id_rsa.pub）添加到GitHub管理平台中，在GitHub的个人账户的设置中找到如下界面</p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/cf68eeaa-0bda-44d7-8ae6-a1eff7f91b2c.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><p>  &nbsp; &nbsp;title随便起一个，将公钥（ id_rsa.pub）文件中内容复制粘贴到key中，然后点击Ass SSH key就好啦</p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/ebc27b77-186f-4f5e-bfd3-f5f07367c854.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250816/71e11da2-3910-49e9-b242-6522954a8768.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p>',0,0,0,0,1755354476,1756184484,NULL),(39,4,'EasyExcel导出字典动态转换','EasyExcel导出字典动态转换','EasyExcel导出字典动态转换','/adminapi/uploads/image/20250816/3d725db7-069c-4b26-916c-ec24d8435660.jpg','Amusing编程喵','<p><strong>一、EasyExcel的Convert转换器</strong></p><pre><code >package com.vehicle.easyexcel;\nimport com.alibaba.excel.converters.Converter;\nimport com.alibaba.excel.enums.CellDataTypeEnum;\nimport com.alibaba.excel.metadata.GlobalConfiguration;\nimport com.alibaba.excel.metadata.data.ReadCellData;\nimport com.alibaba.excel.metadata.data.WriteCellData;\nimport com.alibaba.excel.metadata.property.ExcelContentProperty;\nimport com.vehicle.base.entity.BaseDictItem;\nimport com.vehicle.base.service.BaseDictService;\nimport com.vehicle.common.annotation.DictFormat;\nimport com.vehicle.common.utils.SpringApplicationUtils;\nimport java.lang.reflect.Field;\nimport java.util.List;\npublic class DictConvert implements Converter&lt;String&gt; {\n    private BaseDictService baseDictService;\n    //懒汉模式构造器\n    public DictConvert() {\n        baseDictService = SpringApplicationUtils.getBean(BaseDictService.class);\n    }\n    @Override\n    public Class&lt;Integer&gt; supportJavaTypeKey() {\n        return Integer.class;\n    }\n\n    @Override\n    public CellDataTypeEnum supportExcelTypeKey() {\n        return CellDataTypeEnum.STRING;\n    }\n    /**\n    * 导出\n    */\n    @Override\n    public WriteCellData&lt;?&gt; convertToExcelData(String value, ExcelContentProperty contentProperty, GlobalConfiguration globalConfiguration) {\n        if (value == null)\n            return new WriteCellData&lt;&gt;(\"\");\n        // 获取字典类型\n        Field field = contentProperty.getField();\n        DictFormat excel = field.getAnnotation(DictFormat.class);\n        String res =\"\";\n        if (excel !=null){\n            String dictType = excel.value();\n            List&lt;BaseDictItem&gt; dictItemList = baseDictService.getDict(dictType);\n            for (BaseDictItem baseDictItem : dictItemList) {\n                if (value.equals(baseDictItem.getValue())){\n                    res  = baseDictItem.getLabel();\n                }\n            }\n        } else {\n            res = value;\n        }\n        return new WriteCellData&lt;&gt;(res);\n    }\n    /**\n     * 将excel单元格数据转换成对象属性值（适配多个逗号分隔的字典值） - 导入\n     *\n     * @param cellData             单元格的数据\n     * @param contentProperty excel每一行的数据内容\n     * @param globalConfiguration  global全局配置\n     * @return 转换后的对象属性值\n     * @throws Exception 异常\n     */\n    @Override\n    public String convertToJavaData(ReadCellData&lt;?&gt; cellData, ExcelContentProperty contentProperty, GlobalConfiguration globalConfiguration) throws Exception {\n        return String.valueOf(\"dictValues\");\n    }\n}</code></pre><p><strong>二、自定义的字典注解</strong></p><p><br></p><pre><code >package com.vehicle.common.annotation;\nimport java.lang.annotation.ElementType;\nimport java.lang.annotation.Retention;\nimport java.lang.annotation.RetentionPolicy;\nimport java.lang.annotation.Target;\n@Target({ElementType.FIELD})\n@Retention(RetentionPolicy.RUNTIME)\npublic @interface DictFormat {\n    String value();\n}</code></pre><p><strong>三、Spring工具类</strong></p><pre><code >package com.vehicle.common.utils;\nimport org.springframework.beans.BeansException;\nimport org.springframework.context.ApplicationContext;\nimport org.springframework.context.ApplicationContextAware;\nimport org.springframework.stereotype.Component;\nimport java.util.Map;\n@Component\npublic class SpringApplicationUtils implements ApplicationContextAware {\n    private static ApplicationContext applicationContext = null;\n    /**\n     * 获取applicationContext\n     *\n     * @return\n     */\n    public static ApplicationContext getApplicationContext() {\n        return applicationContext;\n    }\n    @Override\n    public void setApplicationContext(ApplicationContext applicationContext) throws BeansException {\n        if (SpringApplicationUtils.applicationContext == null) {\n            SpringApplicationUtils.applicationContext = applicationContext;\n        }\n    }\n    /**\n     * 通过name获取 Bean.\n     */\n    public static Object getBean(String name) {\n        return getApplicationContext().getBean(name);\n    }\n    /**\n     * 通过class获取Bean.\n     *\n     * @param clazz\n     * @param &lt;T&gt;\n     * @return\n     */\n    public static &lt;T&gt; T getBean(Class&lt;T&gt; clazz) {\n        return getApplicationContext().getBean(clazz);\n    }\n    /**\n     * 通过name,以及Clazz返回指定的Bean\n     *\n     * @param name\n     * @param clazz\n     * @param &lt;T&gt;\n     * @return\n     */\n    public static &lt;T&gt; T getBean(String name, Class&lt;T&gt; clazz) {\n        return getApplicationContext().getBean(name, clazz);\n    }\n    /**\n     * 获取指定类型的所有bean实例\n     *\n     * @param clazz\n     * @param &lt;T&gt;\n     * @return\n     */\n    public static &lt;T&gt; Map&lt;String, T&gt; getBeansOfType(Class&lt;T&gt; clazz) {\n        Map&lt;String, T&gt; instances = getApplicationContext().getBeansOfType(clazz);\n        return instances;\n    }\n}</code></pre><p><strong>四、使用</strong></p><p><br></p><pre><code >@Schema(description = \"可用状态：0：不可用  1：可用\", required = true)\n@TableField(condition = SqlCondition.EQUAL)\n@ExcelProperty( value = \"可用状态\", order = 2,converter = DictConvert.class)\n@DictFormat(\"used_flag\")\nprivate Integer usedFlag;\n\n@ExcelProperty( value = \"可用状态\", order = 2,converter = DictConvert.class)中DictConvert不能少，缺少自定义注解失效\n\n\n</code></pre><p><br></p>',0,0,0,0,1755355350,1756184474,NULL),(40,4,'screw数据库文档生成','screw数据库文档生成','screw数据库文档生成','/adminapi/uploads/image/20250816/7d326435-3bb5-42d4-869c-dcd3c3ac8966.jpg','Amusing编程喵','<p><strong>一、引入Maven依赖</strong></p><pre><code >&lt;!--引入数据库表结构文档生成器Screw依赖--&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;cn.smallbun.screw&lt;/groupId&gt;\n    &lt;artifactId&gt;screw-core&lt;/artifactId&gt;\n    &lt;version&gt;1.0.5&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;!-- Hikari数据库连接池 也可采用阿里巴巴的Druid、C3p0等数据库连接池 --&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;com.zaxxer&lt;/groupId&gt;\n    &lt;artifactId&gt;HikariCP&lt;/artifactId&gt;\n    &lt;version&gt;3.4.2&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;!--mysql驱动--&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;mysql&lt;/groupId&gt;\n    &lt;artifactId&gt;mysql-connector-java&lt;/artifactId&gt;\n    &lt;scope&gt;runtime&lt;/scope&gt;\n&lt;/dependency&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;org.freemarker&lt;/groupId&gt;\n    &lt;artifactId&gt;freemarker&lt;/artifactId&gt;\n    &lt;version&gt;2.3.30&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;!-- sqlserver数据库驱动 --&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;net.sourceforge.jtds&lt;/groupId&gt;\n    &lt;artifactId&gt;jtds&lt;/artifactId&gt;\n    &lt;version&gt;1.3.1&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;com.microsoft.sqlserver&lt;/groupId&gt;\n    &lt;artifactId&gt;mssql-jdbc&lt;/artifactId&gt;\n    &lt;version&gt;6.2.0.jre8&lt;/version&gt;\n    &lt;scope&gt;runtime&lt;/scope&gt;\n&lt;/dependency&gt;</code></pre><p><strong>二、代码实现</strong></p><pre><code >package com.flyedt.utils;\nimport cn.smallbun.screw.core.Configuration;\nimport cn.smallbun.screw.core.engine.EngineConfig;\nimport cn.smallbun.screw.core.engine.EngineFileType;\nimport cn.smallbun.screw.core.engine.EngineTemplateType;\nimport cn.smallbun.screw.core.execute.DocumentationExecute;\nimport cn.smallbun.screw.core.process.ProcessConfig;\nimport com.zaxxer.hikari.HikariConfig;\nimport com.zaxxer.hikari.HikariDataSource;\nimport javax.sql.DataSource;\nimport java.util.ArrayList;\npublic class ScrewStart {\n    public static void main(String[] args) {\n        // 数据源\n        HikariConfig hikariConfig = new HikariConfig();\n        hikariConfig.setDriverClassName(\"com.microsoft.sqlserver.jdbc.SQLServerDriver\");\n        hikariConfig.setJdbcUrl(\"jdbc:sqlserver://49.232.74.234:1433;DatabaseName=flyerp_qdmetro_20200422\");\n        hikariConfig.setUsername(\"sa\");\n        hikariConfig.setPassword(\"Flyedt@qd2022sql\");\n        // 设置可以获取tables remarks信息\n        hikariConfig.addDataSourceProperty(\"useInformationSchema\", \"true\");\n        hikariConfig.setMinimumIdle(2);\n        hikariConfig.setMaximumPoolSize(5);\n        DataSource dataSource = new HikariDataSource(hikariConfig);\n        // 生成配置\n        EngineConfig engineConfig = EngineConfig.builder()\n                // 生成文件路径\n                .fileOutputDir(\"D:\\\\adb\\\\\")\n                // 打开目录 设置为true执行完代码后会自动打开对应路径文件夹\n                .openOutputDir(true)\n                // 文件类型,目前有doc跟html两种类型\n                .fileType(EngineFileType.WORD)\n                // 生成模板实现\n                .produceType(EngineTemplateType.freemarker).build();\n        // 忽略表,这些表不会在文档中生成\n        ArrayList&lt;String&gt; ignoreTableName = new ArrayList&lt;&gt;();\n        ignoreTableName.add(\"test_user\");\n        ignoreTableName.add(\"test_group\");\n        // 忽略表前缀,这些表不会在文档中生成\n        ArrayList&lt;String&gt; ignorePrefix = new ArrayList&lt;&gt;();\n        ignorePrefix.add(\"test_\");\n        // 忽略表后缀,这些表不会在文档中生成\n        ArrayList&lt;String&gt; ignoreSuffix = new ArrayList&lt;&gt;();\n        ignoreSuffix.add(\"_test\");\n        ProcessConfig processConfig = ProcessConfig.builder()\n                // 忽略表名\n                .ignoreTableName(ignoreTableName)\n                // 忽略表前缀\n                .ignoreTablePrefix(ignorePrefix)\n                // 忽略表后缀\n                .ignoreTableSuffix(ignoreSuffix).build();\n        // 配置\n        Configuration config = Configuration.builder()\n                // 版本\n                .version(\"1.0.0\")\n                // 描述\n                .description(\"数据库设计文档1\")\n                // 数据源\n                .dataSource(dataSource)\n                // 生成配置\n                .engineConfig(engineConfig)\n                // 生成配置\n                .produceConfig(processConfig).build();\n        // 执行生成\n        new DocumentationExecute(config).execute();\n    }\n}</code></pre><p><strong>三、支持数据库</strong></p><p> MySQL、MariaDB、TIDB、Oracle、SqlServer、PostgreSQL、Cache DB</p>',0,3,0,0,1755355478,1756184477,NULL),(41,5,'Springboot集成多数据源','Springboot集成多数据源','Springboot集成多数据源','/adminapi/uploads/image/20250817/f3e26753-5299-4b62-af3e-643dffe5fd0f.jpg','Amusing编程喵','<p><strong>一、导入依赖</strong></p><pre><code >&lt;!-- 多数据源支持--&gt;\n &lt;dependency&gt;\n       &lt;groupId&gt;com.baomidou&lt;/groupId&gt;\n        &lt;artifactId&gt;dynamic-datasource-spring-boot-starter&lt;/artifactId&gt;\n        &lt;version&gt;3.1.0&lt;/version&gt;\n &lt;/dependency&gt;</code></pre><p><strong>二、编写yml 配置文件</strong></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;1、以前可能这么写：</span></p><pre><code >spring:\n  datasource:\n    url: jdbc:mysql://127.0.0.1:3306/test?useUnicode=true&characterEncoding=utf-8&autoReconnect=true&useSSL=false\n    username: root\n    password: root\n    driver-class-name: com.mysql.cj.jdbc.Driver</code></pre><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp;2、现在这么写:</span></p><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; primary 属性:代表 后面跟的数据源为主数据源,没有DS注解特殊标识,默认查询的数据源,master和idcdb 就是为数据源起了一个名字,方便后面DS标识</span></p><pre><code >spring:\n  datasource:\n    dynamic:\n      primary: master\n      datasource:\n        master:\n          url: jdbc:mysql://127.0.0.1:3306/ceshi?useUnicode=true&characterEncoding=utf-8&autoReconnect=true&useSSL=false\n          username: root\n          password: root\n          driver-class-name: com.mysql.cj.jdbc.Driver\n        idcdb:\n          url: jdbc:mysql://127.0.0.1:3306/test?useUnicode=true&characterEncoding=utf-8&autoReconnect=true&useSSL=false&serverTimezone=GMT%2B8\n          username: root\n          password: root\n          driver-class-name: com.mysql.cj.jdbc.Driver\n          </code></pre><p><strong>三、实际应用</strong></p><p><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250817/0bd9dcda-a9c2-4ffb-9a0c-e8ce757f715d.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"/></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250817/8ad631a0-5a48-4fbd-be97-0f62bd959232.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><h1><span style=\"font-size: 16px;\"> &nbsp; &nbsp;4、手动切换数据源</span></h1><pre><code >DynamicDataSourceContextHolder.push(\"slave\")即可手动切换数据源。\nDynamicDataSourceContextHolder.clear() 清空当前数据源</code></pre><h1><span style=\"font-size: 16px;\"> &nbsp; &nbsp;5、@Transactional注解导致 多数据源@DS无效 的解决方案</span></h1><p><span style=\"font-size: 16px;\"> &nbsp; &nbsp; 解决方案：把@Transactional替换成@DSTransactional注解即可</span></p><p><strong> &nbsp; &nbsp;6、多数据源开启多线程，数据源问题</strong></p><p style=\"text-align: center;\"><img src=\"https://zy.wlown.com/adminapi/uploads/image/20250817/1210fc3c-999f-48fd-8ce7-18e3944f8c74.png\" alt=\"\" data-href=\"\" style=\"width: 50%;\"></p><pre><code >DynamicDataSourceContextHolder.push(\"qdmetro\");\n\n如果使用多数据源，并且服务间调用，必须都用注解，不然会找不到表（@DS(\"qddt_jssj\")）</code></pre><p><br></p>',0,0,0,0,1755442175,1756184481,NULL),(42,5,'EasyExcel动态表头导出','EasyExcel动态表头导出','EasyExcel动态表头导出','/adminapi/uploads/image/20250816/3d725db7-069c-4b26-916c-ec24d8435660.jpg','Amusing编程喵','<p><strong>一、项目需求</strong></p><p> 请求头的内容、列数不确定，请求头随时更改，所以请求头为动态。</p><p><strong>二、引入jar包</strong></p><pre><code >&lt;!--easyexcel --&gt;\n&lt;dependency&gt;\n   &lt;groupId&gt;com.alibaba&lt;/groupId&gt;\n   &lt;artifactId&gt;easyexcel&lt;/artifactId&gt;\n   &lt;version&gt;3.1.1&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;dependency&gt;\n   &lt;groupId&gt;org.apache.poi&lt;/groupId&gt;\n   &lt;artifactId&gt;poi&lt;/artifactId&gt;\n   &lt;version&gt;3.17&lt;/version&gt;\n&lt;/dependency&gt;\n&lt;dependency&gt;\n   &lt;groupId&gt;org.apache.poi&lt;/groupId&gt;\n   &lt;artifactId&gt;poi-ooxml&lt;/artifactId&gt;\n   &lt;version&gt;3.17&lt;/version&gt;\n&lt;/dependency&gt;</code></pre><p><strong>三、创建工具类</strong></p><pre><code >import com.alibaba.excel.EasyExcel;\nimport org.apache.commons.lang.StringUtils;\nimport javax.servlet.http.HttpServletResponse;\nimport java.io.IOException;\nimport java.io.OutputStream;\nimport java.util.*;\n/**\n* 导出工具类：可以通过easyUtil方法进行导出\n*/\nclass EasyExcelExportUtils {\n    /**\n     *\n     * [response, fileName:文件名称, heads：excel表头, list：数据体]\n     */\n        public static void easyUtil(HttpServletResponse response, String fileName, List&lt;String&gt; heads, List&lt;Map&lt;String, Object&gt;&gt; list)\n        throws IOException {\n        if (StringUtils.isEmpty(fileName)){ //文件名称也可以动态获取\n            fileName = System.currentTimeMillis() + \".xlsx\";\n        } else {\n            fileName = fileName + \".xlsx\";\n        }\n        if(heads == null || heads.size() == 0){\n            heads = makeHeads();\n        }\n        if(list == null || list.size() == 0){\n            list = makeData();\n        }\n        // 调用responseInfo方法\n        OutputStream os= responseInfo(response, fileName);\n        List&lt;List&lt;String&gt;&gt; hs = new ArrayList&lt;&gt;();\n        for (String s : heads) {\n            hs.add(Arrays.asList(s));\n        }\n        List&lt;List&lt;Object&gt;&gt; list2 = new ArrayList&lt;&gt;();\n        for (Map&lt;String, Object&gt; map : list) {\n            List&lt;Object&gt; objects = new ArrayList&lt;&gt;();\n            for (String head : heads) {\n                Object value = map.get(head);\n                    if (value != null){\n                        objects.add(value.toString());\n                    }else {\n                        objects.add(null);\n                    }\n            }\n            list2.add(objects);\n        }\n        EasyExcel.write(os).head(hs).sheet(\"导出的excel文件名称\").doWrite(list2);\n        System.out.println(\"导出成功\");\n    }\n    private static List&lt;String&gt; makeHeads() {\n        return null;\n    }\n    private static List&lt;Map&lt;String, Object&gt;&gt; makeData() {\n        return null;\n    }\n    /**\n     * 功能：公用方法，写回浏览器\n     */\n    public static OutputStream responseInfo(HttpServletResponse response, String fileName) throws IOException {\n        // 这里注意有同学反应使用swagger 会导致各种问题，请直接用浏览器或者用postman\n        response.setContentType(\"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\");\n        response.setCharacterEncoding(\"utf-8\");\n        response.setHeader(\"Content-disposition\", \"attachment; filename*=utf-8\'\'\" + fileName);\n        OutputStream os=response.getOutputStream();\n        return os;\n    }\n    /**\n     * 如果要兼容swagger用这个，上面的注释掉\n     * 功能：公用方法\n     * 参数：fileName 文件名称, 如：123.xlsx\n     public static OutputStream responseInfo(HttpServletResponse response, String fileName) throws IOException {\n     response.setCharacterEncoding(\"utf-8\");\n     response.setContentType(\"APPLICATION/OCTET-STREAM\");\n     response.addHeader(\"Content-Disposition\", \"attachment;filename=\" + fileName);\n     OutputStream os=response.getOutputStream();\n     return os;\n     }\n     */\n}</code></pre><p><strong>四、开始导出</strong></p><pre><code > /**\n     * 动态导出\n     */\n    @GetMapping(\"toOut\")\n    public void testExcel1(HttpServletResponse response) throws IOException {\n        //1.设置动态表头\n        List&lt;String&gt; heads = new ArrayList&lt;&gt;();\n        heads.add(\"第一个头\");\n        heads.add(\"第二个头\");\n        List&lt;Map&lt;String, Object&gt;&gt; list = new ArrayList&lt;&gt;();\n        Map&lt;String, Object&gt; map1= new LinkedHashMap&lt;&gt;();\n        map1.put(\"第一个头\",\"AAA\");\n        map1.put(\"第二个头\",\"BBB\");\n        list.add(map1);\n        Map&lt;String, Object&gt; map2= new LinkedHashMap&lt;&gt;();\n        map2.put(\"第一个头\",\"ccc\");\n        map2.put(\"第二个头\",\"ddd\");\n        list.add(map2);\n        EasyExcelExportUtils.easyUtil(response,\"导出excel的文件名\",heads,list);\n    }\n     /**\n     * 动态导出,兼容swagger,如果使用swagger放开注释，注释掉上面代码\n     * [response]\n     * @return {@link }\n     * @throws\n     * @author 李庆伟\n     * @date 2022/5/31 14:43\n     \n    @GetMapping(\"toOut\")\n    @ApiOperation(value = \"导出全部\", notes = \"导出全部\", produces = MediaType.APPLICATION_OCTET_STREAM_VALUE)    \n    public void testExcel1(HttpServletResponse response) throws IOException {\n        EasyExcelExportUtils.easyUtil(response,\"12345\",null,null);\n    }\n*/</code></pre><p><br></p>',0,0,0,0,1755442341,1755442341,NULL),(43,5,'EasyExcel自适应列宽','EasyExcel自适应列宽','EasyExcel自适应列宽','/adminapi/uploads/image/20250816/3d725db7-069c-4b26-916c-ec24d8435660.jpg','Amusing编程喵','<pre><code >package com.wpg.common.handler;\nimport com.alibaba.excel.enums.CellDataTypeEnum;\nimport com.alibaba.excel.metadata.Head;\nimport com.alibaba.excel.metadata.data.CellData;\nimport com.alibaba.excel.metadata.data.WriteCellData;\nimport com.alibaba.excel.write.metadata.holder.WriteSheetHolder;\nimport com.alibaba.excel.write.style.column.AbstractColumnWidthStyleStrategy;\nimport com.baomidou.mybatisplus.core.toolkit.CollectionUtils;\nimport org.apache.poi.ss.usermodel.Cell;\nimport java.nio.ByteBuffer;\nimport java.nio.CharBuffer;\nimport java.nio.charset.StandardCharsets;\nimport java.util.HashMap;\nimport java.util.List;\nimport java.util.Map;\n/**\n* excel自适应列宽\n*\n*/\npublic class CustomCellWriteHandler extends AbstractColumnWidthStyleStrategy {\n    private static final int MAX_COLUMN_WIDTH = 255;\n    private static final int COLUMN_WIDTH_BASE = 255;\n    private final Map&lt;Integer, Map&lt;Integer, Double&gt;&gt; cache = new HashMap&lt;&gt;(8);\n    private Integer relativeRowIndex = -1;\n    public CustomCellWriteHandler() {\n    }\n    public CustomCellWriteHandler(Integer relativeRowIndex) {\n        //这里是指定从第几行开始自适应。0是第一行，1是第二行，以此类推\n        this.relativeRowIndex = relativeRowIndex;\n    }\n    @Override\n    protected void setColumnWidth(WriteSheetHolder writeSheetHolder, List&lt;WriteCellData&lt;?&gt;&gt; cellDataList, Cell cell, Head head, Integer relativeRowIndex, Boolean isHead) {\n        boolean needSetWidth = isHead || !CollectionUtils.isEmpty(cellDataList);\n        if (needSetWidth) {\n            if(this.relativeRowIndex == -1 || relativeRowIndex &gt;= this.relativeRowIndex){\n                Map&lt;Integer, Double&gt; maxColumnWidthMap = cache.computeIfAbsent(writeSheetHolder.getSheetNo(), k -&gt; new HashMap&lt;&gt;(16));\n                double columnWidth = this.dataLength(cellDataList, cell, isHead);\n                if (columnWidth &gt;= 0) {\n                    if (columnWidth &gt; MAX_COLUMN_WIDTH) {\n                        columnWidth = MAX_COLUMN_WIDTH;\n                    }\n                    Double maxColumnWidth = maxColumnWidthMap.get(cell.getColumnIndex());\n                    if (maxColumnWidth == null || columnWidth &gt; maxColumnWidth) {\n                        maxColumnWidthMap.put(cell.getColumnIndex(), columnWidth);\n                        writeSheetHolder.getSheet().setColumnWidth(cell.getColumnIndex(), (int)(maxColumnWidthMap.get(cell.getColumnIndex())*COLUMN_WIDTH_BASE));\n                    }\n                }\n            }\n        }\n    }\n    private double dataLength(List&lt;WriteCellData&lt;?&gt;&gt; cellDataList, Cell cell, Boolean isHead) {\n        if (isHead) {\n            return cell.getStringCellValue().getBytes().length;\n        } else {\n            CellData&lt;?&gt; cellData = cellDataList.get(0);\n            CellDataTypeEnum type = cellData.getType();\n            if (type == null) {\n                return -1;\n            } else {\n                switch (type) {\n                    case STRING:\n                        return getExcelWidth(cellData.getStringValue());\n                    case BOOLEAN:\n                        return getExcelWidth(cellData.getBooleanValue().toString());\n                    case NUMBER:\n                        return getExcelWidth(cellData.getNumberValue().toString());\n                    default:\n                        return -1;\n                }\n            }\n        }\n    }\n    /**\n     * 调整单元格字符字节宽度，easyExcel默认直接用的UTF-8的byte长度，导致一旦三字节的字符过多就会变得很宽，一字节的字符过多就会不够宽\n     */\n    private double getExcelWidth(String str){\n        double length = 0.0;\n        char[] chars = str.toCharArray();\n        for(char c : chars){\n            byte[] bytes = this.getUtf8Bytes(c);\n            if(bytes.length == 1){\n                length += 1.05;\n            }\n            if(bytes.length == 2){\n                length += 1.5;\n            }\n            if(bytes.length == 3){\n                length += 1.85;\n            }\n            if(bytes.length == 4){\n                length += 2.2;\n            }\n        }\n        return length;\n    }\n    private byte[] getUtf8Bytes(char c) {\n        char[] chars = {c};\n        CharBuffer charBuffer = CharBuffer.allocate(chars.length);\n        charBuffer.put(chars);\n        charBuffer.flip();\n        ByteBuffer byteBuffer = StandardCharsets.UTF_8.encode(charBuffer);\n        return byteBuffer.array();\n    }\n}</code></pre><p><br></p>',0,0,0,0,1755442392,1755442392,NULL),(44,5,'Http工具类 HttpUtils','Http工具类 HttpUtils','Http工具类 HttpUtils','/adminapi/uploads/image/20250817/6d57af70-c63a-4dce-a257-3f479871e616.png','Amusing编程喵','<pre><code >import java.io.IOException;\nimport java.nio.charset.Charset;\nimport java.security.KeyManagementException;\nimport java.security.KeyStore;\nimport java.security.KeyStoreException;\nimport java.security.NoSuchAlgorithmException;\nimport java.security.cert.CertificateException;\nimport java.security.cert.X509Certificate;\nimport java.util.ArrayList;\nimport java.util.List;\nimport java.util.Map;\nimport java.util.Map.Entry;\nimport javax.net.ssl.SSLContext;\nimport com.alibaba.fastjson.JSONObject;\nimport org.apache.http.HttpEntity;\nimport org.apache.http.NameValuePair;\nimport org.apache.http.ParseException;\nimport org.apache.http.client.ClientProtocolException;\nimport org.apache.http.client.entity.UrlEncodedFormEntity;\nimport org.apache.http.client.methods.CloseableHttpResponse;\nimport org.apache.http.client.methods.HttpGet;\nimport org.apache.http.client.methods.HttpPost;\nimport org.apache.http.config.ConnectionConfig;\nimport org.apache.http.config.Registry;\nimport org.apache.http.config.RegistryBuilder;\nimport org.apache.http.config.SocketConfig;\nimport org.apache.http.conn.socket.ConnectionSocketFactory;\nimport org.apache.http.conn.socket.LayeredConnectionSocketFactory;\nimport org.apache.http.conn.socket.PlainConnectionSocketFactory;\nimport org.apache.http.conn.ssl.SSLConnectionSocketFactory;\nimport org.apache.http.conn.ssl.SSLContexts;\nimport org.apache.http.conn.ssl.TrustStrategy;\nimport org.apache.http.impl.client.CloseableHttpClient;\nimport org.apache.http.impl.client.HttpClientBuilder;\nimport org.apache.http.impl.conn.PoolingHttpClientConnectionManager;\nimport org.apache.http.message.BasicHeader;\nimport org.apache.http.message.BasicNameValuePair;\nimport org.apache.http.util.EntityUtils;\n/**\n* &lt;p&gt;类名: HttpUtils&lt;/p&gt;\n* &lt;p&gt;描述: http请求工具类&lt;/p&gt;\n*\n*/\npublic class HttpUtils {\n    public static String defaultEncoding = \"utf-8\";\n    /**\n     * 发送http post请求，并返回响应实体\n     *\n     * @param url 请求地址\n     * @return url响应实体\n     */\n    public static String postRequest(String url) {\n        return postRequest(url, null, null);\n    }\n    /**\n     * &lt;p&gt;方法名: postRequest&lt;/p&gt;\n     * &lt;p&gt;描述: 发送httpPost请求&lt;/p&gt;\n     *\n     * @param url\n     * @param params\n     * @return\n     */\n    public static String postRequest(String url, Map&lt;String, Object&gt; params) {\n        return postRequest(url, null, params);\n    }\n    /**\n     * 发送http post请求，并返回响应实体\n     *\n     * @param url     访问的url\n     * @param headers 请求需要添加的请求头\n     * @param params  请求参数\n     * @return\n     */\n    public static String postRequest(String url, Map&lt;String, String&gt; headers,\n                                     Map&lt;String, Object&gt; params) {\n        String result = null;\n        CloseableHttpClient httpClient = buildHttpClient();\n        HttpPost httpPost = new HttpPost(url);\n        if (null != headers && headers.size() &gt; 0) {\n            for (Entry&lt;String, String&gt; entry : headers.entrySet()) {\n                String key = entry.getKey();\n                String value = entry.getValue();\n                httpPost.addHeader(new BasicHeader(key, value));\n            }\n        }\n        if (null != params && params.size() &gt; 0) {\n            List&lt;NameValuePair&gt; pairList = new ArrayList&lt;NameValuePair&gt;(params.size());\n            for (Map.Entry&lt;String, Object&gt; entry : params.entrySet()) {\n                NameValuePair pair = new BasicNameValuePair(entry.getKey(), entry.getValue().toString());\n                pairList.add(pair);\n            }\n            httpPost.setEntity(new UrlEncodedFormEntity(pairList, Charset.forName(defaultEncoding)));\n        }\n        try {\n            CloseableHttpResponse response = httpClient.execute(httpPost);\n            try {\n                HttpEntity entity = response.getEntity();\n                if (entity != null) {\n                    result = EntityUtils.toString(entity,\n                            Charset.forName(defaultEncoding));\n                }\n            } finally {\n                response.close();\n            }\n        } catch (Exception ex) {\n            ex.printStackTrace();\n        } finally {\n            try {\n                httpClient.close();\n            } catch (IOException e) {\n                e.printStackTrace();\n            }\n        }\n        return result;\n    }\n    /**\n     * 发送http get请求\n     *\n     * @param url 请求url\n     * @return url返回内容\n     */\n    public static String getRequest(String url) {\n        return getRequest(url, null);\n    }\n    /**\n     * 发送http get请求\n     *\n     * @param url    请求的url\n     * @param params 请求的参数\n     * @return\n     */\n    public static String getRequest(String url, Map&lt;String, Object&gt; params) {\n        return getRequest(url, null, params);\n    }\n    /**\n     * 发送http get请求\n     *\n     * @param url        请求的url\n     * @param headersMap 请求头\n     * @param params     请求的参数\n     * @return\n     */\n    public static String getRequest(String url, Map&lt;String, String&gt; headersMap, Map&lt;String, Object&gt; params) {\n        String result = null;\n        CloseableHttpClient httpClient = buildHttpClient();\n        try {\n            String apiUrl = url;\n            if (null != params && params.size() &gt; 0) {\n                StringBuffer param = new StringBuffer();\n                int i = 0;\n                for (String key : params.keySet()) {\n                    if (i == 0)\n                        param.append(\"?\");\n                    else\n                        param.append(\"&\");\n                    param.append(key).append(\"=\").append(params.get(key));\n                    i++;\n                }\n                apiUrl += param;\n            }\n            HttpGet httpGet = new HttpGet(apiUrl);\n            if (null != headersMap && headersMap.size() &gt; 0) {\n                for (Entry&lt;String, String&gt; entry : headersMap.entrySet()) {\n                    String key = entry.getKey();\n                    String value = entry.getValue();\n                    httpGet.addHeader(new BasicHeader(key, value));\n                }\n            }\n            CloseableHttpResponse response = httpClient.execute(httpGet);\n            try {\n                HttpEntity entity = response.getEntity();\n                if (null != entity) {\n                    result = EntityUtils.toString(entity, defaultEncoding);\n                }\n            } finally {\n                response.close();\n            }\n        } catch (ClientProtocolException e) {\n            e.printStackTrace();\n        } catch (ParseException e) {\n            e.printStackTrace();\n        } catch (IOException e) {\n            e.printStackTrace();\n        } finally {\n            try {\n                httpClient.close();\n            } catch (IOException e) {\n                e.printStackTrace();\n            }\n        }\n        return result;\n    }\n    /**\n     * 创建httpclient\n     *\n     * @return\n     */\n    public static CloseableHttpClient buildHttpClient() {\n        try {\n            RegistryBuilder&lt;ConnectionSocketFactory&gt; builder = RegistryBuilder\n                    .create();\n            ConnectionSocketFactory factory = new PlainConnectionSocketFactory();\n            builder.register(\"http\", factory);\n            KeyStore trustStore = KeyStore.getInstance(KeyStore\n                    .getDefaultType());\n            SSLContext context = SSLContexts.custom().useTLS()\n                    .loadTrustMaterial(trustStore, new TrustStrategy() {\n                        public boolean isTrusted(X509Certificate[] chain,\n                                                 String authType) throws CertificateException {\n                            return true;\n                        }\n                    }).build();\n            LayeredConnectionSocketFactory sslFactory = new SSLConnectionSocketFactory(\n                    context,\n                    SSLConnectionSocketFactory.ALLOW_ALL_HOSTNAME_VERIFIER);\n            builder.register(\"https\", sslFactory);\n            Registry&lt;ConnectionSocketFactory&gt; registry = builder.build();\n            PoolingHttpClientConnectionManager manager = new PoolingHttpClientConnectionManager(\n                    registry);\n            ConnectionConfig connConfig = ConnectionConfig.custom()\n                    .setCharset(Charset.forName(defaultEncoding)).build();\n            SocketConfig socketConfig = SocketConfig.custom()\n                    .setSoTimeout(100000).build();\n            manager.setDefaultConnectionConfig(connConfig);\n            manager.setDefaultSocketConfig(socketConfig);\n            return HttpClientBuilder.create().setConnectionManager(manager)\n                    .build();\n        } catch (KeyStoreException e) {\n            e.printStackTrace();\n        } catch (KeyManagementException e) {\n            e.printStackTrace();\n        } catch (NoSuchAlgorithmException e) {\n            e.printStackTrace();\n        }\n        return null;\n    }\n    public static void main(String[] args) {\n        String url = \"http://127.0.0.1:8080/user/login\";\n       \n        JSONObject params = new JSONObject();\n        params.put(\"username\", \"test\");\n        params.put(\"password\", \"123456\");\n        String result = HttpUtils.postRequest(url, params);\n        System.out.println(result);\n    }\n}\n</code></pre><p><br></p>',0,0,0,0,1755442481,1755442481,NULL),(45,5,'Http工具类（失败重试）','Http工具类（失败重试）','Http工具类（失败重试）','/adminapi/uploads/image/20250817/6d57af70-c63a-4dce-a257-3f479871e616.png','Amusing编程喵','<pre><code >package com.xfs.common.utils;\nimport com.alibaba.fastjson.JSONObject;\nimport org.apache.http.HttpEntity;\nimport org.apache.http.HttpEntityEnclosingRequest;\nimport org.apache.http.HttpRequest;\nimport org.apache.http.NoHttpResponseException;\nimport org.apache.http.client.ClientProtocolException;\nimport org.apache.http.client.HttpRequestRetryHandler;\nimport org.apache.http.client.config.RequestConfig;\nimport org.apache.http.client.methods.CloseableHttpResponse;\nimport org.apache.http.client.methods.HttpPost;\nimport org.apache.http.client.methods.HttpRequestBase;\nimport org.apache.http.client.protocol.HttpClientContext;\nimport org.apache.http.conn.ConnectTimeoutException;\nimport org.apache.http.entity.StringEntity;\nimport org.apache.http.impl.client.CloseableHttpClient;\nimport org.apache.http.impl.client.HttpClients;\nimport org.apache.http.impl.conn.PoolingHttpClientConnectionManager;\nimport org.apache.http.protocol.HttpContext;\nimport org.apache.http.util.EntityUtils;\nimport javax.annotation.PostConstruct;\nimport javax.net.ssl.SSLException;\nimport java.io.IOException;\nimport java.io.UnsupportedEncodingException;\nimport java.net.UnknownHostException;\nimport java.nio.charset.Charset;\nimport java.util.logging.Logger;\n/**\n* HttpClientUtlis工具类\n* (增加重试重试次数)\n*/\npublic class WeiFangIotHttpUtils {\n    static final int timeOut = 30 * 1000;\n    static Logger log = Logger.getLogger(\"HttpClientUtils\");\n    private static PoolingHttpClientConnectionManager cm = null;\n    private static void config(HttpRequestBase httpRequestBase) {\n        // 配置请求的超时设置\n        RequestConfig requestConfig = RequestConfig.custom()\n                .setConnectionRequestTimeout(timeOut)\n                .setConnectTimeout(timeOut).setSocketTimeout(timeOut).build();\n        httpRequestBase.setConfig(requestConfig);\n    }\n\n    @PostConstruct\n    public void init() {\n        cm = new PoolingHttpClientConnectionManager();\n        cm.setMaxTotal(1000);\n        cm.setDefaultMaxPerRoute(1000);\n    }\n    /**\n     * @param isPooled 是否使用连接池\n     */\n    public static CloseableHttpClient getClient(boolean isPooled) {\n        HttpRequestRetryHandler handler = new HttpRequestRetryHandler() {\n            @Override\n            public boolean retryRequest(IOException arg0, int retryTimes, HttpContext arg2) {\n                log.info(\"&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;第\"+retryTimes+\"次请求&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;\");\n                if (retryTimes &gt; 2) {\n                    return false;\n                }\n                if (arg0 instanceof UnknownHostException || arg0 instanceof ConnectTimeoutException\n                        || !(arg0 instanceof SSLException) || arg0 instanceof NoHttpResponseException) {\n                    log.info(\"&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;异常重试&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;\");\n                    return true;\n                }\n                HttpClientContext clientContext = HttpClientContext.adapt(arg2);\n                HttpRequest request = clientContext.getRequest();\n                boolean idempotent = !(request instanceof HttpEntityEnclosingRequest);\n                if (idempotent) {\n                    // 如果请求被认为是幂等的，那么就重试。即重复执行不影响程序其他效果的\n                    log.info(\"&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;幂等重试&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;&gt;\");\n                    return true;\n                }\n                return false;\n            }\n        };\n        if (isPooled) {\n            return HttpClients.custom().setConnectionManager(cm).setRetryHandler(handler).build();\n        }\n        return HttpClients.createDefault();\n    }\n    /**\n     * +\n     * post请求\n     *\n     * @param url         请求路径\n     * @param requestBody post请求体\n     */\n    public static String post(String url, JSONObject requestBody) {\n        CloseableHttpClient httpClient = getClient(true);\n        String data = null;\n        // 创建httpPost\n        HttpPost httppost = new HttpPost(url);\n        config(httppost);\n        // 创建参数队列\n        if (requestBody != null) {\n            StringEntity entity = new StringEntity(requestBody.toJSONString(), Charset.forName(\"UTF-8\"));\n            entity.setContentEncoding(\"UTF-8\");\n            // 发送Json格式的数据请求\n            entity.setContentType(\"application/json\");\n            httppost.setEntity(entity);\n        }\n        try {\n//            log.info(\"httpClientPost请求地址：{}\", httppost.getURI());\n            try (CloseableHttpResponse response = httpClient.execute(httppost)) {\n                HttpEntity entity = response.getEntity();\n                if (entity != null) {\n                    data = EntityUtils.toString(entity, \"UTF-8\");\n                }\n            }\n        } catch (ClientProtocolException e) {\n            e.printStackTrace();\n        } catch (UnsupportedEncodingException e1) {\n            e1.printStackTrace();\n        } catch (IOException e) {\n            e.printStackTrace();\n        } finally {\n            // 关闭连接,释放资源\n            try {\n                httpClient.close();\n            } catch (IOException e) {\n                e.printStackTrace();\n            }\n        }\n        return data;\n    }\n}\n</code></pre><p><br></p>',0,0,0,0,1755442714,1755442714,NULL),(46,5,'Java从服务器下载文件并保存到本地','Java从服务器下载文件并保存到本地','Java从服务器下载文件并保存到本地','/adminapi/uploads/image/20250811/88a2ccb8-73a3-49be-b25c-20cefa6fecd1.png','Amusing编程喵','<p><strong>一、基础知识</strong></p><p><span style=\"font-size: 16px;\"> &nbsp;当我们想要下载网站上的某个资源时，我们会获取一个url，它是服务器定位资源的一个描述，下载的过程有如下几步：</span></p><p><span style=\"font-size: 16px;\"> &nbsp;（1）客户端发起一个url请求，获取连接对象。</span></p><p><span style=\"font-size: 16px;\"> &nbsp;（2）服务器解析url，并且将指定的资源返回一个输入流给客户。</span></p><p><span style=\"font-size: 16px;\"> &nbsp;（3）建立存储的目录以及保存的文件名。</span></p><p><span style=\"font-size: 16px;\"> &nbsp;（4）输出了写数据。</span></p><p><span style=\"font-size: 16px;\"> &nbsp;（5）关闭输入流和输出流。</span></p><p><strong>二、实现代码的方法</strong></p><pre><code > /**\n     * @功能 下载临时素材接口\n     * @param filePath 文件将要保存的目录\n     * @param method 请求方法，包括POST和GET\n     * @param url 请求的路径\n     * @return\n     */\n    public static File saveUrlAs(String url,String filePath,String method){\n         //System.out.println(\"fileName----&gt;\"+filePath);\n         //创建不同的文件夹目录\n         File file=new File(filePath);\n         //判断文件夹是否存在\n         if (!file.exists())\n        {\n            //如果文件夹不存在，则创建新的的文件夹\n             file.mkdirs();\n        }\n         FileOutputStream fileOut = null;\n         HttpURLConnection conn = null;\n         InputStream inputStream = null;\n         try\n        {\n             // 建立链接\n             URL httpUrl=new URL(url);\n             conn=(HttpURLConnection) httpUrl.openConnection();\n             //以Post方式提交表单，默认get方式\n             conn.setRequestMethod(method);\n             conn.setDoInput(true);  \n             conn.setDoOutput(true);\n             // post方式不能使用缓存\n             conn.setUseCaches(false);\n             //连接指定的资源\n             conn.connect();\n             //获取网络输入流\n             inputStream=conn.getInputStream();\n             BufferedInputStream bis = new BufferedInputStream(inputStream);\n             //判断文件的保存路径后面是否以/结尾\n             if (!filePath.endsWith(\"/\")) {\n                 filePath += \"/\";\n                 }\n             //写入到文件（注意文件保存路径的后面一定要加上文件的名称）\n             fileOut = new FileOutputStream(filePath+\"123.png\");\n             BufferedOutputStream bos = new BufferedOutputStream(fileOut);\n             byte[] buf = new byte[4096];\n             int length = bis.read(buf);\n             //保存文件\n             while(length != -1)\n             {\n                 bos.write(buf, 0, length);\n                 length = bis.read(buf);\n             }\n             bos.close();\n             bis.close();\n             conn.disconnect();\n        } catch (Exception e)\n        {\n             e.printStackTrace();\n             System.out.println(\"抛出异常！！\");\n        }\n         return file;\n     }</code></pre><h3 style=\"line-height: 1.5;\"><span style=\"font-size: 16px;\">三、代码测试类（主函数）</span></h3><pre><code >/**\n     * @param args\n */\npublic static void main(String[] args)\n {\n        String photoUrl = \"https://ss0.bdstatic.com/5aV1bjqh_Q23odCf/static/superman/img/logo/bd_logo1_31bdc765.png\";                                    \n        String fileName = photoUrl.substring(photoUrl.lastIndexOf(\"/\"));\n        //System.out.println(\"fileName----&gt;\"+fileName);\n        String filePath = \"d:\";  \n        File file = saveUrlAs(photoUrl, filePath + fileName,\"GET\");  \n        System.out.println(\"Run ok!/n&lt;BR&gt;Get URL file \" + file);  \n }</code></pre><p><br></p>',0,0,0,0,1755442867,1755442867,NULL),(47,5,'Java读取文件路径中的文件转成json,然后转成实体','Java读取文件路径中的文件转成json,然后转成实体','Java读取文件路径中的文件转成json,然后转成实体','/adminapi/uploads/image/20250817/61a5dcd4-6a77-4381-9c2c-751614abb08f.jpeg','Amusing编程喵','<p><strong>一、引入maven</strong></p><pre><code >&lt;dependency&gt;\n      &lt;groupId&gt;cn.hutool&lt;/groupId&gt;\n      &lt;artifactId&gt;hutool-poi&lt;/artifactId&gt;\n      &lt;version&gt;5.8.2&lt;/version&gt;\n&lt;/dependency&gt;</code></pre><p> <strong>二、解析txt文件</strong></p><pre><code >/**\n     * 转json\n     *\n     * @param jsonPath jsonPath\n     * @param type 返回实体\n     * @return 实体\n     */\npublic static &lt;T&gt; T readJson(String jsonPath, Class&lt;T&gt; type) {\n        String s = null;\n        String s1 = null;\n        String s2 = null;\n        try {\n            s = FileUtil.readString(jsonPath, CharsetUtil.charset(\"UTF-8\"));\n            s1 = FileUtil.readString(new File(\"D:\\\\7号线二期工程指标-源文件.txt\"), \"UTF-8\");\n            s2 = FileUtils.readFileToString(new File(\"D:\\\\7号线二期工程指标-源文件.txt\"), \"UTF-8\");\n        } catch (IORuntimeException e) {\n            log.debug(\"文件不存在原因 {}\", e.getMessage());\n        }\n        return JsonUtils.fromJson(s, type);\n}\n注意：如果txt解析中文乱码，将txt读取utf-8格式</code></pre><p><br></p>',0,0,0,0,1755443149,1755443149,NULL),(48,5,'Spring常用注解及其他','Spring常用注解及其他','Spring常用注解及其他','/adminapi/uploads/image/20250817/52b6dc15-e836-482e-9b02-92581d6d5e8e.jpeg','Amusing编程喵','<p><strong>一、非数据字段注解</strong></p><pre><code >-- mybatis\n@TableField(exist = false) 注解加载bean属性上\n-- hibernate   javax.persistence.Transient\n@Transient</code></pre><p><strong>二、实体类保持驼峰法或大小写</strong></p><pre><code >@JsonProperty(\"FolderName\")\nprivate String FolderName;</code></pre><p><strong>三、接收下划线参数</strong></p><pre><code >@JsonProperty(\"a_attr\")</code></pre><p><strong>四、Config使用constant</strong></p><pre><code >@Bean(name = DatasourceConstant.QDDT_JSSJ)\n\npublic interface DatasourceConstant {\n    /**\n     * 结算审计\n     */\n    String QDDT_JSSJ = \"mysql\";\n}</code></pre><p><strong>五、数字开头的字段</strong></p><pre><code >private String _1keyGUID;\n可以接收\n1keyGUID json数据</code></pre><p> </p><p><br></p>',0,0,0,0,1755443385,1755443385,NULL),(49,5,'日期转换工具类','日期转换工具类','日期转换工具类','/adminapi/uploads/image/20250817/c801bf25-d296-4dac-8d28-f5f5dec73ec0.jpg','Amusing编程喵','<pre><code >package com.flyedt.utils;\nimport lombok.extern.slf4j.Slf4j;\nimport org.apache.commons.lang3.StringUtils;\nimport org.apache.commons.net.PrintCommandListener;\nimport org.apache.commons.net.ftp.FTP;\nimport org.apache.commons.net.ftp.FTPReply;\nimport org.apache.commons.net.ftp.FTPSClient;\nimport org.apache.commons.net.util.TrustManagerUtils;\nimport java.io.*;\nimport java.nio.charset.StandardCharsets;\nimport java.text.SimpleDateFormat;\nimport java.time.Instant;\nimport java.time.LocalDateTime;\nimport java.time.ZoneId;\nimport java.time.ZonedDateTime;\nimport java.util.Calendar;\nimport java.util.Date;\nimport java.util.StringTokenizer;\nimport java.util.UUID;\n/**\n* 日期转换\n*/\n@Slf4j\npublic class TransDateUtils {\n\n    public static SimpleDateFormat format = new SimpleDateFormat(\"yyyy-MM-dd\");\n    public static SimpleDateFormat format1 = new SimpleDateFormat(\n            \"yyyy-MM-dd HH:mm:ss\");\n\n    /**\n     * date转LocalDateTime\n     * @param date\n     * @return\n     */\n    public static LocalDateTime dateToLocalDateTime(Date date) {\n        Instant instant = date.toInstant();\n        LocalDateTime localDateTime = LocalDateTime.ofInstant(instant, ZoneId.systemDefault());\n        return localDateTime;\n    }\n\n    /**\n     * 计算日期\n     * @return\n     */\n    public static Long calculateDays(Date beginTime,Date endTime){\n        long millisecondsPerDay = 24 * 60 * 60 * 1000;\n        long diff = Math.abs(endTime.getTime() - beginTime.getTime());\n        // 计算工期\n        long planDuration = diff / millisecondsPerDay;\n        return planDuration;\n    }\n\n    /**\n     * LocalDateTime转date\n     * @param date\n     * @return\n     */\n    public static Date localDateTimeToDate(LocalDateTime date) {\n        ZonedDateTime zonedDateTime = date.atZone(ZoneId.systemDefault());\n        Instant instant2 = zonedDateTime.toInstant();\n        Date date2 = Date.from(instant2);\n        return date2;\n    }\n\n    /**\n     * 日期计算\n     * @param startTime\n     * @param days\n     * @return\n     */\n    public static Date calculateDateByDate(Date startTime,Integer days){\n\n\n        Calendar calendar = Calendar.getInstance();\n        calendar.setTime(startTime);\n        calendar.add(Calendar.DATE,days);\n        return calendar.getTime();\n    }\n    /**\n     * 获取当天开始时间\n     * @return\n     */\n    public static Date getStartDate(){\n        // 获取当前日期\n        Calendar calendar = Calendar.getInstance();\n        // 设置时间为当天的开始时间\n        calendar.set(Calendar.HOUR_OF_DAY, 0);\n        calendar.set(Calendar.MINUTE, 0);\n        calendar.set(Calendar.SECOND, 0);\n        calendar.set(Calendar.MILLISECOND, 0);\n        Date startOfDay = calendar.getTime();\n        return startOfDay;\n    }\n\n    /**\n     * 获取当天结束时间\n     * @return\n     */\n    public static Date getEndDate(){\n        // 获取当前日期\n        Calendar calendar = Calendar.getInstance();\n        // 设置时间为当天的结束时间\n        calendar.set(Calendar.HOUR_OF_DAY, 23);\n        calendar.set(Calendar.MINUTE, 59);\n        calendar.set(Calendar.SECOND, 59);\n        calendar.set(Calendar.MILLISECOND, 999);\n        Date endOfDay = calendar.getTime();\n        return endOfDay;\n    }\n\n    /**\n     * 获取下一个周几\n     * @return\n     */\n    public static Date getNextWeekDate(int currentDayOfWeek,int targetDayOfWeek){\n\n        // 计算差集\n        int dayDiff = (targetDayOfWeek - currentDayOfWeek + 7) % 7;\n        // 创建当前日期\n        Calendar nextDate = Calendar.getInstance();\n        nextDate.setTime(Calendar.getInstance().getTime());\n        // 添加相差天数\n        nextDate.add(Calendar.DAY_OF_MONTH,dayDiff);\n        // 获取下一个周几的日期\n        return nextDate.getTime();\n    }\n\n    /**\n     * 得到指定日期的一天的的最后时刻23:59:59\n     *\n     * @param date\n     * @return\n     */\n    public static Date getFinallyDate(Date date) {\n        String temp = format.format(date);\n        temp += \" 23:59:59\";\n        try {\n            return format1.parse(temp);\n        } catch (Exception e) {\n            throw new RuntimeException(e.getMessage());\n        }\n    }\n\n    /**\n     * 得到指定日期的一天的开始时刻00:00:00\n     *\n     * @param date\n     * @return\n     */\n    public static Date getStartDate(Date date) {\n        String temp = format.format(date);\n        temp += \" 00:00:00\";\n        try {\n            return format1.parse(temp);\n        } catch (Exception e) {\n            throw new RuntimeException(e.getMessage());\n        }\n    }\n\n    /**\n     * 字符串转时间\n     * @param date\n     * @return\n     */\n    public static Date stringToDate(String date) {\n        try {\n            return format1.parse(date  + \" 00:00:00\");\n        } catch (Exception e) {\n            throw new RuntimeException(e.getMessage());\n        }\n    }\n\n    /**\n     * 获取年份\n     * @param index\n     * @return\n     */\n    public static int getYear(int index){\n        Calendar calendar = Calendar.getInstance();\n        int year = calendar.get(Calendar.YEAR);\n        if (index &gt;= 0){\n            // 设置为去年\n            calendar.set(Calendar.YEAR, year + index);\n        }else {\n            calendar.set(Calendar.YEAR, year - Math.abs(index));\n        }\n        int lastYear = calendar.get(Calendar.YEAR);\n        return lastYear;\n    }\n\n}</code></pre><p><br></p>',0,0,0,0,1755443492,1755443687,NULL),(50,5,'身份证号码生成工具类','身份证号码生成工具类','身份证号码生成工具类','/adminapi/uploads/image/20250817/f0b17728-7936-4bb4-ba41-8d8fa57adb4e.jpg','Amusing编程喵','<pre><code >public class IdCardGenerator {  \n\n    public static final Map&lt;String, Integer&gt; areaCode = new HashMap&lt;String, Integer&gt;();  \n\n    static {  \n        IdCardGenerator.areaCode.put(\"北京市\", 110000);  \n        IdCardGenerator.areaCode.put(\"市辖区\", 110100);  \n        IdCardGenerator.areaCode.put(\"东城区\", 110101);  \n        