/*Table structure for table `la_comment` */

DROP TABLE IF EXISTS `la_comment`;

CREATE TABLE `la_comment` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `parent_id` int(11) DEFAULT NULL COMMENT '评论父级的id',
  `reply_id` int(11) DEFAULT NULL COMMENT '被回复评论的id',
  `reply_name` varchar(100) CHARACTER SET latin1 DEFAULT NULL COMMENT '被回复人名称',
  `user_id` int(11) NOT NULL COMMENT '用户id',
  `user_avatar` varchar(300) CHARACTER SET latin1 DEFAULT NULL COMMENT '用户头像地址',
  `user_content` varchar(500) CHARACTER SET latin1 NOT NULL COMMENT '用户评论内容',
  `is_like` tinyint(1) DEFAULT NULL COMMENT '用户是否点赞',
  `like_count` int(11) DEFAULT NULL COMMENT '点赞数统计',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `article_id` int(11) NOT NULL COMMENT '文章id',
  `user_name` varchar(100) DEFAULT NULL COMMENT '用户名',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='评论';

/*Data for the table `la_comment` */

/*Table structure for table `la_config` */

DROP TABLE IF EXISTS `la_config`;

CREATE TABLE `la_config` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `type` varchar(30) DEFAULT NULL COMMENT '类型',
  `name` varchar(60) NOT NULL DEFAULT '' COMMENT '名称',
  `value` text COMMENT '值',
  `create_time` int(10) DEFAULT NULL COMMENT '创建时间',
  `update_time` int(10) DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=55 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='配置表';

