/*Table structure for table `plan_habit` */

DROP TABLE IF EXISTS `plan_habit`;

CREATE TABLE `plan_habit` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(100) NOT NULL COMMENT '习惯名称',
  `description` text COMMENT '描述',
  `icon` varchar(50) DEFAULT NULL COMMENT '图标',
  `color` varchar(20) DEFAULT '#52C41A' COMMENT '颜色',
  `target_days` int(11) DEFAULT '30' COMMENT '目标天数',
  `frequency_type` tinyint(4) DEFAULT '1' COMMENT '频率类型(1:每天 2:每周 3:自定义)',
  `frequency_rule` varchar(100) DEFAULT NULL COMMENT '频率规则',
  `start_date` date DEFAULT NULL COMMENT '开始日期',
  `reminder_time` varchar(50) DEFAULT NULL COMMENT '提醒时间',
  `status` tinyint(4) DEFAULT '0' COMMENT '状态(0:进行中 1:已完成 2:已放弃)',
  `current_days` int(11) DEFAULT '0' COMMENT '当前连续天数',
  `total_days` int(11) DEFAULT '0' COMMENT '累计打卡天数',
  `user_id` bigint(20) DEFAULT NULL COMMENT '用户ID',
  `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(4) DEFAULT '0' COMMENT '删除标志(0:正常 1:删除)',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='习惯表';

