/*Table structure for table `plan_schedule_event` */

DROP TABLE IF EXISTS `plan_schedule_event`;

CREATE TABLE `plan_schedule_event` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(200) NOT NULL COMMENT '日程标题',
  `content` text COMMENT '日程内容',
  `event_type` tinyint(4) DEFAULT '1' COMMENT '日程类型(1:日程 2:待办)',
  `quadrant` tinyint(4) DEFAULT '2' COMMENT '四象限(1:重要紧急 2:重要不紧急 3:紧急不重要 4:不紧急不重要)',
  `priority` tinyint(4) DEFAULT '2' COMMENT '优先级(1:低 2:中 3:高)',
  `category_id` bigint(20) DEFAULT NULL COMMENT '分类ID',
  `start_time` datetime DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '结束时间',
  `is_all_day` tinyint(4) DEFAULT '0' COMMENT '是否全天(0:否 1:是)',
  `is_repeat` tinyint(4) DEFAULT '0' COMMENT '是否重复(0:否 1:是)',
  `repeat_type` tinyint(4) DEFAULT NULL COMMENT '重复类型(1:每日 2:每周 3:每月 4:每年)',
  `repeat_rule` varchar(100) DEFAULT NULL COMMENT '重复规则JSON',
  `remind_time` varchar(200) DEFAULT NULL COMMENT '提醒时间(多个逗号分隔)',
  `location` varchar(200) DEFAULT NULL COMMENT '地点',
  `status` tinyint(4) DEFAULT '0' COMMENT '状态(0:未完成 1:已完成)',
  `completed_time` datetime DEFAULT NULL COMMENT '完成时间',
  `user_id` bigint(20) DEFAULT NULL COMMENT '用户ID',
  `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `del_flag` tinyint(4) DEFAULT '0' COMMENT '删除标志(0:正常 1:删除)',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_category_id` (`category_id`),
  KEY `idx_start_time` (`start_time`),
  KEY `idx_quadrant` (`quadrant`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='日程事件表';

