/*Table structure for table `sys_camera` */

DROP TABLE IF EXISTS `sys_camera`;

CREATE TABLE `sys_camera` (
  `id` varchar(32) NOT NULL COMMENT '主键ID',
  `name` varchar(100) NOT NULL COMMENT '设备名称',
  `ip` varchar(50) NOT NULL COMMENT 'IP地址',
  `port` int(11) DEFAULT '554' COMMENT 'RTSP端口',
  `rtsp_url` varchar(255) DEFAULT NULL COMMENT 'RTSP完整地址',
  `username` varchar(50) DEFAULT NULL COMMENT '认证用户名',
  `password` varchar(100) DEFAULT NULL COMMENT '认证密码(加密存储)',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态: 0-离线 1-在线',
  `wifi_ssid` varchar(100) DEFAULT NULL COMMENT '所属WiFi名称',
  `wifi_bssid` varchar(50) DEFAULT NULL COMMENT 'WiFi MAC地址',
  `manufacturer` varchar(100) DEFAULT NULL COMMENT '设备厂商',
  `model` varchar(100) DEFAULT NULL COMMENT '设备型号',
  `thumbnail` varchar(255) DEFAULT NULL COMMENT '缩略图URL',
  `stream_url` varchar(255) DEFAULT NULL COMMENT '转流后的HLS地址',
  `last_online_time` datetime DEFAULT NULL COMMENT '最后在线时间',
  `last_stream_time` datetime DEFAULT NULL COMMENT '最后播放时间',
  `play_count` int(11) DEFAULT '0' COMMENT '播放次数',
  `sort` int(11) DEFAULT '0' COMMENT '排序',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_user` int(11) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_user` int(11) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '是否删除: 0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_ip` (`ip`),
  KEY `idx_status` (`status`),
  KEY `idx_wifi_ssid` (`wifi_ssid`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='摄像头设备表';

